const normalizeImageBatchSize = (value) => {
  const parsed = Math.floor(Number(value));
  if (!Number.isFinite(parsed)) return IMAGE_BATCH_SIZE_DEFAULT;
  return Math.max(IMAGE_BATCH_SIZE_DEFAULT, parsed);
};

