const setCreditStatus = (text, loading = false) => {
  if (creditValue) creditValue.textContent = text;
  if (creditSpinner) creditSpinner.classList.toggle('active', loading);
};

const fetchCredits = async () => {
  const key = currentApiKey || apiKeyInput.value.trim();
  if (!key) {
    setCreditStatus('—', false);
    return;
  }
  setCreditStatus(creditValue?.textContent || '…', true);
  try {
    const res = await fetch(`${API_BASE}/chat/credit`, {
      headers: { Authorization: `Bearer ${key}` }
    });
    const data = await res.json();
    if (data.code !== 200) {
      setCreditStatus('Error', false);
      return;
    }
    const credits = Number.isFinite(data.data) ? data.data : data.data ?? '—';
    setCreditStatus(`${credits}`, false);
  } catch (err) {
    setCreditStatus('Offline', false);
  }
};

const startCreditPolling = () => {
  if (creditTimer) clearInterval(creditTimer);
  fetchCredits();
  creditTimer = setInterval(fetchCredits, 20000);
};

