const loadAvatars = () => {
  try {
    const raw = localStorage.getItem(AVATARS_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) return [];
    const cleanPath = (value = '') => {
      const rawPath = String(value || '').trim();
      if (!rawPath) return '';
      if (!rawPath.startsWith('file://')) return rawPath;
      try {
        let out = decodeURIComponent(new URL(rawPath).pathname || '');
        if (/^\/[A-Za-z]:/.test(out)) out = out.slice(1);
        return out;
      } catch (_err) {
        return rawPath.replace(/^file:\/\//i, '');
      }
    };
    const isSupabase = (url = '') => /(^https?:\/\/)?[^/]*supabase\.co\//i.test(String(url || ''));
    const sanitizeAvatarAsset = (entry = {}) => {
      const localPath = cleanPath(entry.localPath || entry.path || '');
      const uploadedUrl = String(entry.uploadedUrl || entry.value || '').trim();
      return {
        ...entry,
        path: localPath,
        localPath,
        uploadedUrl: isSupabase(uploadedUrl) ? '' : uploadedUrl
      };
    };
    return parsed.map((avatar) => ({
      ...avatar,
      profile: avatar?.profile ? sanitizeAvatarAsset(avatar.profile) : null,
      images: Array.isArray(avatar?.images) ? avatar.images.map(sanitizeAvatarAsset) : [],
      clothes: Array.isArray(avatar?.clothes) ? avatar.clothes.map(sanitizeAvatarAsset) : [],
      greenScreen: Array.isArray(avatar?.greenScreen) ? avatar.greenScreen.map(sanitizeAvatarAsset) : []
    }));
  } catch (err) {
    log('Could not read avatars.');
    return [];
  }
};

