const loadObjectDraft = () => {
  try {
    const raw = localStorage.getItem(OBJECT_DRAFT_KEY);
    if (!raw) return;
    const draft = JSON.parse(raw);
    if (objectNameInput && draft?.name) objectNameInput.value = draft.name;
    if (objectDescInput && draft?.description) objectDescInput.value = draft.description;
    if (objectEnvPromptInput) {
      objectEnvPromptInput.value = draft?.environmentPrompt || '';
    }
    objectBaseSource = hydrateObjectImage(draft?.baseImage);
    objectEnvironmentSource = hydrateObjectImage(draft?.environmentImage);
    renderObjectBasePreview();
    renderObjectEnvironmentPreview();
    if (Array.isArray(draft?.images) && draft.images.length) {
      objectSources = draft.images.map((img) => ({
        type: img.type || (img.uploadedUrl ? 'url' : 'file'),
        path: img.localPath || img.path || '',
        localPath: img.localPath || img.path || '',
        name: img.name || '',
        label: img.label || img.name || img.uploadedUrl || '',
        mime: img.mime || '',
        uploadedUrl: img.uploadedUrl || '',
        value: img.uploadedUrl || '',
        thumbData: img.thumbData || '',
        preview: img.localPath ? `file://${img.localPath}` : img.uploadedUrl || img.thumbData || ''
      }));
    }
  } catch (err) {
    log('Could not load object draft.');
  }
};

