const loadActivityCache = () => {
  const empty = {
    records: [],
    currentPage: 0,
    totalPages: 1,
    hasMore: true,
    updatedAt: 0
  };
  if (!ACTIVITY_CACHE_ENABLED) {
    try {
      localStorage.removeItem(ACTIVITY_CACHE_KEY);
    } catch (_err) {}
    return empty;
  }
  try {
    const raw = localStorage.getItem(ACTIVITY_CACHE_KEY);
    if (!raw) return empty;
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== 'object') return empty;
    const sourceRows = Array.isArray(parsed.records) ? parsed.records : [];
    const records = sourceRows
      .slice(0, ACTIVITY_CACHE_MAX_ROWS)
      .map((row, idx) => normalizeActivityRecord(row, idx, 1))
      .sort((a, b) => getActivitySortValue(b) - getActivitySortValue(a));
    const currentPage = Math.max(0, Number(parsed.currentPage || 0));
    const totalPages = Math.max(1, Number(parsed.totalPages || 1));
    const hasMore = typeof parsed.hasMore === 'boolean' ? parsed.hasMore : currentPage < totalPages;
    const updatedAt = Math.max(0, Number(parsed.updatedAt || 0));
    return {
      records,
      currentPage,
      totalPages,
      hasMore,
      updatedAt
    };
  } catch (_err) {
    return empty;
  }
};

const persistActivityCache = (
  rows = activityRecords,
  { currentPage = activityCurrentPage, totalPages = activityTotalPages, hasMore = activityHasMorePages, updatedAt = Date.now() } = {}
) => {
  if (!ACTIVITY_CACHE_ENABLED) {
    try {
      localStorage.removeItem(ACTIVITY_CACHE_KEY);
    } catch (_err) {}
    return;
  }
  try {
    const safeRows = (Array.isArray(rows) ? rows : [])
      .slice(0, ACTIVITY_CACHE_MAX_ROWS)
      .map((row, idx) => {
        const normalized = normalizeActivityRecord(row, idx, 1);
        return {
          id: String(normalized.id || ''),
          taskId: String(normalized.taskId || ''),
          state: String(normalized.state || ''),
          model: String(normalized.model || ''),
          createTime: Number(normalized.createTime || 0),
          updateTime: Number(normalized.updateTime || 0),
          completeTime: Number(normalized.completeTime || 0),
          failMsg: String(normalized.failMsg || ''),
          failCode: String(normalized.failCode || ''),
          prompt: String(normalized.prompt || ''),
          resultUrls: rankActivityMediaUrls(Array.isArray(normalized.resultUrls) ? normalized.resultUrls : []).slice(0, 10),
          urls: rankActivityMediaUrls(Array.isArray(normalized.urls) ? normalized.urls : []).slice(0, 12),
          taskLookupState: String(normalized.taskLookupState || ''),
          resultLookupState: String(normalized.resultLookupState || ''),
          resultLookupMessage: String(normalized.resultLookupMessage || '')
        };
      });
    localStorage.setItem(
      ACTIVITY_CACHE_KEY,
      JSON.stringify({
        records: safeRows,
        currentPage: Math.max(0, Number(currentPage) || 0),
        totalPages: Math.max(1, Number(totalPages) || 1),
        hasMore: !!hasMore,
        updatedAt: Math.max(0, Number(updatedAt) || Date.now())
      })
    );
  } catch (_err) {}
};

const restoreActivityCacheFromStorage = () => {
  if (!ACTIVITY_CACHE_ENABLED) {
    try {
      localStorage.removeItem(ACTIVITY_CACHE_KEY);
    } catch (_err) {}
    return false;
  }
  const cached = loadActivityCache();
  if (!cached.records.length) return false;
  activityRecords = cached.records;
  activityCurrentPage = Math.max(0, Number(cached.currentPage || 0));
  activityTotalPages = Math.max(1, Number(cached.totalPages || 1));
  activityHasMorePages = !!cached.hasMore;
  activityVisibleItemCount = Math.min(
    Math.max(ACTIVITY_VISIBLE_ITEM_BATCH, Number(activityVisibleItemCount || 0)),
    activityRecords.length
  );
  activityLastSuccessfulLoadAt = Math.max(0, Number(cached.updatedAt || 0));
  activityFeedInitialized =
    activityLastSuccessfulLoadAt > 0 &&
    Date.now() - activityLastSuccessfulLoadAt <= ACTIVITY_AUTO_REFRESH_COOLDOWN_MS;
  return true;
};

const normalizeTaskIdCandidate = (value = '') => {
  const text = String(value || '').trim();
  if (!text) return '';

  const hexMatches = text.toLowerCase().match(/[0-9a-f]{24,64}/g) || [];
  if (hexMatches.length) {
    const counts = new Map();
    hexMatches.forEach((hex) => counts.set(hex, (counts.get(hex) || 0) + 1));
    const sorted = [...counts.entries()].sort((a, b) => {
      if (b[1] !== a[1]) return b[1] - a[1];
      return b[0].length - a[0].length;
    });
    const bestHex = String(sorted[0]?.[0] || '').trim();
    if (bestHex) return bestHex;
  }

  const taskPrefixed = text.match(/\b(task[_-]?[A-Za-z0-9_-]{6,})\b/i);
  if (taskPrefixed && taskPrefixed[1]) {
    const candidate = String(taskPrefixed[1]).trim();
    if (!/^task-\d{10,}$/i.test(candidate)) return candidate;
  }

  const compact = text.replace(/^[^A-Za-z0-9_-]+|[^A-Za-z0-9_-]+$/g, '');
  if (!compact) return '';
  if (compact.length < 6 || compact.length > 140) return '';
  if (/\s/.test(compact)) return '';
  if (!/^[A-Za-z0-9_-]+$/.test(compact)) return '';
  if (/^task-\d{10,}$/i.test(compact)) return '';
  return compact;
};

const activityTraceLabel = (value = '') => {
  const text = String(value || '').trim();
  if (!text) return 'n/a';
  if (text.length <= 14) return text;
  return `${text.slice(0, 8)}...${text.slice(-4)}`;
};

const logActivityImageTrace = (step = '', payload = {}) => {
  const data = payload && typeof payload === 'object' ? payload : {};
  const taskId = activityTraceLabel(data.taskId || data.rawTaskId || data.id || '');
  const page = Number(data.pageNum || data.page || 0) || 0;
  const row = Number(data.rowIndex ?? data.index ?? -1);
  const prefix = `[Activity][ImageTrace][${String(step || 'unknown')}]`;
  const tags = [];
  if (taskId !== 'n/a') tags.push(`task=${taskId}`);
  if (page > 0) tags.push(`page=${page}`);
  if (row >= 0) tags.push(`row=${row}`);
  const suffix = tags.length ? ` ${tags.join(' ')}` : '';
  const line = `${prefix}${suffix}`;
  console.info(line, data);
  if (typeof pushActivityScrapeLog === 'function') {
    pushActivityScrapeLog(line, { level: 'info', details: data });
  }
};

const TASK_ID_KEY_PATTERN = /(^taskId$)|(^taskID$)|(^task_id$)|(^taskid$)|(^avatar_talk_task_id$)/i;

const collectTaskIdsFromNode = (node, out, depth = 0) => {
  if (!node || depth > 14) return;
  if (Array.isArray(node)) {
    node.forEach((entry) => collectTaskIdsFromNode(entry, out, depth + 1));
    return;
  }
  if (typeof node !== 'object') return;
  Object.entries(node).forEach(([key, value]) => {
    if (TASK_ID_KEY_PATTERN.test(key)) {
      if (Array.isArray(value)) {
        value.forEach((entry) => {
          const normalized = normalizeTaskIdCandidate(entry);
          if (normalized) out.add(normalized);
        });
      } else {
        const normalized = normalizeTaskIdCandidate(value);
        if (normalized) out.add(normalized);
      }
    }
    if (key === 'id' && Array.isArray(node.urls) && node.urls.length) {
      const normalized = normalizeTaskIdCandidate(value);
      if (normalized) out.add(normalized);
    }
    if (value && typeof value === 'object') {
      collectTaskIdsFromNode(value, out, depth + 1);
    }
  });
};

const collectLocalTaskIdCandidates = () => {
  const out = new Set();
  const add = (value) => {
    const normalized = normalizeTaskIdCandidate(value);
    if (normalized) out.add(normalized);
  };

  add(currentTaskId);
  knownTaskIds.forEach((id) => add(id));

  generations.forEach((entry) => {
    add(entry?.taskId);
    if (Array.isArray(entry?.urls) && entry.urls.length) add(entry?.id);
    collectTaskIdsFromNode(entry, out);
  });

  [saves, sessionSaves, savedBatches].forEach((list) => {
    collectTaskIdsFromNode(list, out);
  });

  try {
    const raw = localStorage.getItem(LAST_ACTIVE_PROJECT_KEY);
    if (raw) {
      const parsed = JSON.parse(raw);
      collectTaskIdsFromNode(parsed, out);
    }
  } catch (_err) {}

  return Array.from(out);
};

const persistKnownTaskIds = (list = []) => {
  const normalized = Array.from(
    new Set(
      (Array.isArray(list) ? list : [])
        .map((id) => normalizeTaskIdCandidate(id))
        .filter(Boolean)
    )
  ).slice(0, 600);
  knownTaskIds = normalized;
  localStorage.setItem(KNOWN_TASK_IDS_KEY, JSON.stringify(normalized));
};

const registerKnownTaskId = (taskId = '') => {
  const normalized = normalizeTaskIdCandidate(taskId);
  if (!normalized) return;
  persistKnownTaskIds([normalized, ...knownTaskIds]);
};

const ensureKnownTaskIdsBackfilled = () => {
  const discovered = collectLocalTaskIdCandidates();
  if (!discovered.length) return;
  const merged = Array.from(new Set([...discovered, ...knownTaskIds]));
  if (merged.length !== knownTaskIds.length) {
    persistKnownTaskIds(merged);
  }
};

const loadBatches = () => {
  try {
    const raw = localStorage.getItem(BATCHES_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? parsed : [];
  } catch (err) {
    log('Could not read batches.');
    return [];
  }
};

const persistBatches = (list) => {
  savedBatches = list;
  localStorage.setItem(BATCHES_KEY, JSON.stringify(list));
};

const loadPresets = () => {
  try {
    const raw = localStorage.getItem(PRESETS_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? parsed : [];
  } catch (err) {
    log('Could not read presets.');
    return [];
  }
};

const persistPresets = (list) => {
  presets = list;
  localStorage.setItem(PRESETS_KEY, JSON.stringify(list));
};

const loadTikTokScripts = () => [];

const persistTikTokScripts = (list) => {
  tiktokScripts = list;
  scheduleSave();
};

const getCombinedSaves = () => {
  const combined = [
    ...sessionSaves.map((s) => ({ ...s, session: true })),
    ...saves.map((s) => ({ ...s, session: false }))
  ];
  return combined.sort((a, b) => (b.updatedAt || b.createdAt || 0) - (a.updatedAt || a.createdAt || 0));
};

const findSaveByName = (name) => {
  if (!name) return { save: null, session: false };
  const session = sessionSaves.find((s) => s.name === name);
  if (session) return { save: session, session: true };
  const persisted = saves.find((s) => s.name === name);
  if (persisted) return { save: persisted, session: false };
  return { save: null, session: false };
};

const getSaveTypeLabel = (type) => {
  if (type === 'batch') return 'Batch';
  if (type === 'video') return 'Sora Video';
  if (type === 'tiktok') return 'TikTok Script';
  if (type === 'avatar') return 'Avatar';
  return 'Image';
};

const generateSessionId = () => {
  if (window.crypto?.randomUUID) return window.crypto.randomUUID();
  return `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
};

const ensureSessionSaveIds = () => {
  let changed = false;
  sessionSaves = sessionSaves.map((s) => {
    if (s.id) return s;
    changed = true;
    return { ...s, id: generateSessionId() };
  });
  if (changed) persistSessionSaves(sessionSaves);
};

const resolveSessionSave = (record) => {
  if (!record) return null;
  if (record.id) {
    return sessionSaves.find((s) => s.id === record.id) || record;
  }
  return sessionSaves.find((s) => s.name === record.name) || record;
};

const renameSessionRecord = (record, nextName) => {
  if (!record) return false;
  const trimmed = (nextName || '').trim();
  if (!trimmed || trimmed === record.name) return false;
  const sessionId = record.id;
  const conflict = sessionSaves.some((s) => s.name === trimmed && (!sessionId || s.id !== sessionId));
  if (conflict) return false;
  sessionSaves = sessionSaves.map((s) => {
    if ((sessionId && s.id === sessionId) || (!sessionId && s.name === record.name)) {
      return { ...s, name: trimmed, updatedAt: Date.now() };
    }
    return s;
  });
  persistSessionSaves(sessionSaves.slice(0, 50));
  if (activeSaveIsSession && activeSaveName === record.name) {
    setActiveSave(trimmed, { session: true, skipCapture: true });
  } else {
    renderOpenTabs();
    renderSavesList();
  }
  return true;
};

const getUniquePersistedName = (baseName) => {
  const base = (baseName || '').trim() || UNTITLED_PREFIX;
  if (!saves.some((s) => s.name === base)) return base;
  let idx = 2;
  while (saves.some((s) => s.name === `${base} ${idx}`)) idx += 1;
  return `${base} ${idx}`;
};

const persistSessionSaveAsPermanent = (record) => {
  if (!record) return null;
  const name = getUniquePersistedName(record.name);
  const savedRecord = {
    name,
    type: record.type || 'image',
    data: JSON.parse(JSON.stringify(record.data || {})),
    updatedAt: Date.now(),
    createdAt: record.createdAt || Date.now()
  };
  saves.unshift(savedRecord);
  persistSaves(saves.slice(0, 50));
  renderSavesList();
  return savedRecord;
};

const isUntitledName = (name = '') => name.startsWith(UNTITLED_PREFIX);

const isRecordPersisted = (record) =>
  !!record && saves.some((s) => s.name === record.name && (s.type || 'image') === (record.type || 'image'));

const persistSessionSaveToExisting = (record) => {
  if (!record) return null;
  const idx = saves.findIndex((s) => s.name === record.name);
  if (idx === -1) return persistSessionSaveAsPermanent(record);
  const updated = {
    ...saves[idx],
    data: JSON.parse(JSON.stringify(record.data || {})),
    updatedAt: Date.now()
  };
  saves[idx] = updated;
  persistSaves(saves.slice(0, 50));
  renderSavesList();
  return updated;
};

const promptForSaveName = () => {
  const input = window.prompt('Name this save (leave blank to close without saving)', '');
  if (input === null) return '';
  return input.trim();
};

const isSaveNameTaken = (name) => {
  const trimmed = (name || '').trim();
  if (!trimmed) return false;
  return [...saves, ...sessionSaves].some((s) => s.name === trimmed);
};

const renameSaveRecord = (record, nextName) => {
  if (!record) return false;
  const trimmed = (nextName || '').trim();
  if (!trimmed) {
    setStatus('Name required', true);
    return false;
  }
  if (trimmed === record.name) return false;
  if (isSaveNameTaken(trimmed)) {
    setStatus('Name already used', true);
    return false;
  }

  let sessionUpdated = false;
  const sessionIdx = record.id
    ? sessionSaves.findIndex((s) => s.id === record.id)
    : sessionSaves.findIndex((s) => s.name === record.name);
  if (sessionIdx >= 0) {
    sessionSaves[sessionIdx] = {
      ...sessionSaves[sessionIdx],
      name: trimmed,
      updatedAt: Date.now()
    };
    sessionUpdated = true;
  }

  let persistedUpdated = false;
  const saveIdx = saves.findIndex((s) => s.name === record.name);
  if (saveIdx >= 0) {
    saves[saveIdx] = {
      ...saves[saveIdx],
      name: trimmed,
      updatedAt: Date.now()
    };
    persistedUpdated = true;
  }

  if (sessionUpdated) persistSessionSaves(sessionSaves.slice(0, 50));
  if (persistedUpdated) persistSaves(saves.slice(0, 50));

  if (activeSaveName === record.name) {
    setActiveSave(trimmed, { session: activeSaveIsSession || sessionUpdated, skipCapture: true });
  }
  renderOpenTabs();
  renderSavesList();
  setStatus(`Renamed to "${trimmed}"`);
  return true;
};

const openRenameModal = (record) => {
  if (!renameModal || !renameModalInput || !record) return;
  const latest = resolveSessionSave(record) || record;
  pendingRenameRecord = latest;
  if (renameModalTitle) renameModalTitle.textContent = `Rename "${latest.name}"`;
  renameModalInput.value = latest.name || '';
  renameModal.classList.add('show');
  setTimeout(() => {
    renameModalInput.focus();
    renameModalInput.select();
  }, 50);
};

const closeRenameModal = () => {
  if (renameModal) renameModal.classList.remove('show');
  pendingRenameRecord = null;
};

const confirmSaveSessionTab = (record) => {
  if (!record) return false;
  if (isRecordPersisted(record)) {
    persistSessionSaveToExisting(record);
    return true;
  }
  if (isUntitledName(record.name) && !isRecordPersisted(record)) {
    const named = promptForSaveName();
    if (!named) return false;
    const savedRecord = persistSessionSaveAsPermanent({ ...record, name: named });
    if (savedRecord) {
      setStatus(`Saved "${savedRecord.name}"`);
      return true;
    }
    return false;
  }
  const shouldSave = window.confirm(`Save "${record.name}" before closing?`);
  if (!shouldSave) return false;
  const savedRecord = isRecordPersisted(record)
    ? persistSessionSaveToExisting(record)
    : persistSessionSaveAsPermanent(record);
  if (savedRecord) {
    setStatus(`Saved "${savedRecord.name}"`);
    return true;
  }
  return false;
};

const activateSaveRecord = (record, { session = false, reason = 'tab' } = {}) => {
  if (!record) return;
  if (activeSaveName && activeSaveName !== record.name) {
    captureActiveSaveState();
  }
  setActiveSave(record.name, { session, skipCapture: true });
  const type = record.type || 'image';
  if (type === 'batch') {
    applyBatchState(record.data || {});
    setCreateView('batch');
  } else if (type === 'video') {
    applyVideoState(record.data || {});
    setCreateView('video');
  } else if (type === 'tiktok') {
    applyTikTokState(record.data || {});
    setCreateView('tiktok');
  } else {
    applyState(record.data || {});
    setCreateView('image');
  }
  setActiveView('builder', { force: true, reason });
};

const openSaveInSession = (save) => {
  if (!save) return null;
  let existing = sessionSaves.find((s) => s.name === save.name && s.type === save.type);
  if (existing) {
    if (!existing.id) {
      const updated = { ...existing, id: generateSessionId() };
      sessionSaves = sessionSaves.map((s) => (s === existing ? updated : s));
      persistSessionSaves(sessionSaves.slice(0, 50));
      existing = updated;
    }
    activateSaveRecord(existing, { session: true, reason: 'activate-existing' });
    return existing;
  }
  const record = {
    id: generateSessionId(),
    name: save.name,
    type: save.type || 'image',
    data: JSON.parse(JSON.stringify(save.data || {})),
    updatedAt: Date.now(),
    createdAt: save.createdAt || Date.now(),
    session: true
  };
  sessionSaves.unshift(record);
  persistSessionSaves(sessionSaves.slice(0, 50));
  activateSaveRecord(record, { session: true, reason: 'activate-new' });
  renderSavesList();
  renderOpenTabs();
  return record;
};

const renderOpenTabs = () => {
  if (!openTabsEl) return;
  if (!sessionSaves.length) {
    openTabsEl.classList.add('hidden');
    openTabsEl.innerHTML = '';
    return;
  }
  openTabsEl.classList.remove('hidden');
  openTabsEl.innerHTML = '';
  sessionSaves.forEach((save, idx) => {
    const tab = document.createElement('div');
    tab.className = `tab${activeSaveName === save.name && activeSaveIsSession ? ' active' : ''}`;
    if (save.id) tab.dataset.sessionId = save.id;

    const title = document.createElement('div');
    title.className = 'tab-title';

    const nameBtn = document.createElement('button');
    nameBtn.type = 'button';
    nameBtn.className = 'tab-name';
    nameBtn.textContent = save.name;
    nameBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      openRenameModal(save);
    });

    const editBtn = document.createElement('button');
    editBtn.type = 'button';
    editBtn.className = 'tab-edit';
    editBtn.textContent = '✎';
    editBtn.title = 'Rename';
    editBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      openRenameModal(save);
    });

    title.appendChild(nameBtn);
    title.appendChild(editBtn);

    const type = document.createElement('span');
    type.className = 'type';
    type.textContent = getSaveTypeLabel(save.type);

    const close = document.createElement('button');
    close.className = 'close';
    close.textContent = '×';
    close.addEventListener('click', (e) => {
      e.stopPropagation();
      if (activeSaveName === save.name && activeSaveIsSession) {
        captureActiveSaveState();
      }
      const latest = resolveSessionSave(save);
      openTabCloseModal(latest);
    });

    tab.appendChild(title);
    tab.appendChild(type);
    tab.appendChild(close);
    tab.addEventListener('click', () => activateSaveRecord(save, { session: true, reason: 'tab-click' }));
    openTabsEl.appendChild(tab);
  });
};

const closeSessionTab = (record) => {
  if (!record) return;
  const activeRecord = activeSaveIsSession ? sessionSaves.find((s) => s.name === activeSaveName) : null;
  let idx = -1;
  let useId = false;
  if (record.id) {
    idx = sessionSaves.findIndex((s) => s.id === record.id);
    useId = idx >= 0;
  }
  if (idx === -1 && record.name) {
    idx = sessionSaves.findIndex((s) => s.name === record.name);
  }
  if (idx === -1) return;
  const removed = sessionSaves[idx];
  if (useId && removed.id) {
    sessionSaves = sessionSaves.filter((s) => s.id !== removed.id);
  } else {
    sessionSaves = sessionSaves.filter((s) => s.name !== removed.name);
  }
  persistSessionSaves(sessionSaves);
  const nameMatches = activeSaveIsSession && activeSaveName && activeSaveName === removed.name;
  const idMatches =
    activeSaveIsSession && activeRecord?.id && removed.id && activeRecord.id === removed.id;
  const wasActive = useId ? idMatches || nameMatches : nameMatches;
  if (wasActive) {
    const next = sessionSaves[idx] || sessionSaves[idx - 1] || sessionSaves[0];
    if (next) {
      activateSaveRecord(next, { session: true, reason: 'tab-close' });
    } else {
      setActiveSave('', { session: false, skipCapture: true });
      setActiveView('create', { force: true, reason: 'tab-close' });
      setCreateView('chooser');
    }
  }
  renderOpenTabs();
  renderSavesList();
};

const openTabCloseModal = (record) => {
  if (!tabCloseModal || !record) return;
  pendingCloseMode = 'tab';
  const latest = resolveSessionSave(record);
  if (latest && isRecordPersisted(latest)) {
    persistSessionSaveToExisting(latest);
    closeSessionTab(latest);
    return;
  }
  pendingTabClose = latest || record;
  const alreadySaved = isRecordPersisted(pendingTabClose);
  const needsName = isUntitledName(pendingTabClose.name) && !alreadySaved;
  if (tabCloseMessage) {
    tabCloseMessage.textContent = needsName
      ? 'Name this tab to save it. Leave blank to close without saving.'
      : `Save "${pendingTabClose.name}" before closing?`;
  }
  if (tabCloseNameRow) tabCloseNameRow.classList.toggle('hidden', !needsName);
  if (tabCloseNameInput) {
    tabCloseNameInput.value = needsName ? pendingTabClose.name : '';
    if (needsName) {
      setTimeout(() => tabCloseNameInput.focus(), 50);
    }
  }
  tabCloseModal.classList.add('show');
};

const openMenuSaveModal = (record) => {
  if (!tabCloseModal || !record) return;
  pendingCloseMode = 'menu';
  const latest = resolveSessionSave(record) || record;
  pendingTabClose = latest;
  const alreadySaved = isRecordPersisted(latest);
  const needsName = isUntitledName(latest.name) && !alreadySaved;
  if (tabCloseMessage) {
    tabCloseMessage.textContent = needsName
      ? 'Name this save to store it.'
      : `Save "${latest.name}" now?`;
  }
  if (tabCloseNameRow) tabCloseNameRow.classList.toggle('hidden', !needsName);
  if (tabCloseNameInput) {
    tabCloseNameInput.value = needsName ? latest.name : '';
    if (needsName) {
      setTimeout(() => tabCloseNameInput.focus(), 50);
    }
  }
  tabCloseModal.classList.add('show');
};

const respondToAppClose = (allow) => {
  if (window.electronAPI?.respondToAppClose) {
    if (allow) appCloseAuthorized = true;
    window.electronAPI.respondToAppClose(allow);
  }
};

const getUnsavedSessionTabs = () => sessionSaves.filter((s) => !isRecordPersisted(s));

const openAppCloseModal = (record) => {
  if (!tabCloseModal || !record) return;
  const latest = resolveSessionSave(record) || record;
  pendingCloseMode = 'app';
  pendingTabClose = latest;
  const alreadySaved = isRecordPersisted(latest);
  const needsName = isUntitledName(latest.name) && !alreadySaved;
  if (tabCloseMessage) {
    tabCloseMessage.textContent = needsName
      ? 'Name this save to keep it before closing the app.'
      : `Save "${latest.name}" before closing the app?`;
  }
  if (tabCloseNameRow) tabCloseNameRow.classList.toggle('hidden', !needsName);
  if (tabCloseNameInput) {
    tabCloseNameInput.value = needsName ? latest.name : '';
    if (needsName) {
      setTimeout(() => tabCloseNameInput.focus(), 50);
    }
  }
  tabCloseModal.classList.add('show');
};

const startAppCloseFlow = () => {
  if (appCloseActive) return;
  captureActiveSaveState();
  appCloseQueue = getUnsavedSessionTabs();
  if (!appCloseQueue.length) {
    respondToAppClose(true);
    return;
  }
  appCloseActive = true;
  openAppCloseModal(appCloseQueue[0]);
};

const advanceAppCloseFlow = (cancelled = false) => {
  if (!appCloseActive) return;
  if (cancelled) {
    appCloseActive = false;
    appCloseQueue = [];
    respondToAppClose(false);
    return;
  }
  appCloseQueue.shift();
  if (!appCloseQueue.length) {
    appCloseActive = false;
    respondToAppClose(true);
    return;
  }
  openAppCloseModal(appCloseQueue[0]);
};

const handleAppClosePrompts = () => {
  captureActiveSaveState();
  const pending = getUnsavedSessionTabs();
  if (!pending.length) {
    appCloseAuthorized = true;
    return true;
  }
  pending.forEach((tab) => {
    if (isUntitledName(tab.name)) {
      const named = window.prompt(
        'Name this save to keep it before closing (leave blank to discard)',
        tab.name
      );
      const trimmed = (named || '').trim();
      if (trimmed) {
        persistSessionSaveAsPermanent({ ...tab, name: trimmed });
      }
      return;
    }
    const shouldSave = window.confirm(`Save "${tab.name}" before closing?`);
    if (shouldSave) {
      persistSessionSaveAsPermanent(tab);
    }
  });
  appCloseAuthorized = true;
  return true;
};

window.__confirmAppClose = handleAppClosePrompts;

const closeTabCloseModal = () => {
  if (tabCloseModal) tabCloseModal.classList.remove('show');
  pendingTabClose = null;
  pendingCloseMode = 'tab';
};

const serializeImages = () => imageSources.map((img) => ({
  type: img.type,
  value: img.value || '',
  label: img.label || '',
  path: img.path || '',
  localPath: img.localPath || '',
  name: img.name || '',
  originalType: img.originalType || '',
  uploadedUrl: img.uploadedUrl || ''
}));

const serializeState = () => ({
  model: modelInput.value.trim(),
  aspect_ratio: aspectRatioSelect.value,
  resolution: resolutionSelect.value,
  output_format: formatSelect.value,
  image_batch_size: normalizeImageBatchSize(imageBatchSizeInput?.value),
  prompt: promptInput.value,
  images: serializeImages(),
  avatar: activeAvatarName || '',
  object: activeObjectName || ''
});

const serializeVideoImages = () =>
  videoSources.map((img) => ({
    type: img.type || 'file',
    value: img.value || '',
    label: img.label || '',
    path: img.path || '',
    localPath: img.localPath || '',
    name: img.name || '',
    mime: img.mime || '',
    uploadedUrl: img.uploadedUrl || '',
    thumbData: img.thumbData || '',
    origin: img.origin || ''
  }));

const clampFinalKeyingValue = (value, min, max, fallback) => {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) return fallback;
  return Math.max(min, Math.min(max, parsed));
};

const normalizeTikTokFinalKeyingSettings = (raw = {}) => ({
  greenSimilarity: clampFinalKeyingValue(
    raw.greenSimilarity,
    0.05,
    0.45,
    TIKTOK_FINAL_KEYING_DEFAULTS.greenSimilarity
  ),
  greenBlend: clampFinalKeyingValue(raw.greenBlend, 0, 0.2, TIKTOK_FINAL_KEYING_DEFAULTS.greenBlend),
  blackSimilarity: clampFinalKeyingValue(
    raw.blackSimilarity,
    0.005,
    0.2,
    TIKTOK_FINAL_KEYING_DEFAULTS.blackSimilarity
  ),
  blackBlend: clampFinalKeyingValue(raw.blackBlend, 0, 0.12, TIKTOK_FINAL_KEYING_DEFAULTS.blackBlend)
});

const loadTikTokFinalKeyingSettings = () => {
  try {
    const raw = localStorage.getItem(TIKTOK_FINAL_KEYING_PREFS_KEY);
    if (!raw) return { ...TIKTOK_FINAL_KEYING_DEFAULTS };
    const parsed = JSON.parse(raw);
    return normalizeTikTokFinalKeyingSettings(parsed || {});
  } catch (_err) {
    return { ...TIKTOK_FINAL_KEYING_DEFAULTS };
  }
};

const persistTikTokFinalKeyingSettings = () => {
  try {
    localStorage.setItem(
      TIKTOK_FINAL_KEYING_PREFS_KEY,
      JSON.stringify(normalizeTikTokFinalKeyingSettings(tiktokFinalKeyingSettings))
    );
  } catch (_err) {}
};

const syncTikTokFinalKeyingInputs = () => {
  if (tiktokFinalGreenSimilarityInput) tiktokFinalGreenSimilarityInput.value = tiktokFinalKeyingSettings.greenSimilarity.toFixed(3);
  if (tiktokFinalGreenBlendInput) tiktokFinalGreenBlendInput.value = tiktokFinalKeyingSettings.greenBlend.toFixed(3);
  if (tiktokFinalBlackSimilarityInput) tiktokFinalBlackSimilarityInput.value = tiktokFinalKeyingSettings.blackSimilarity.toFixed(3);
  if (tiktokFinalBlackBlendInput) tiktokFinalBlackBlendInput.value = tiktokFinalKeyingSettings.blackBlend.toFixed(3);
  if (tiktokFinalGreenSimilarityValue) tiktokFinalGreenSimilarityValue.textContent = tiktokFinalKeyingSettings.greenSimilarity.toFixed(3);
  if (tiktokFinalGreenBlendValue) tiktokFinalGreenBlendValue.textContent = tiktokFinalKeyingSettings.greenBlend.toFixed(3);
  if (tiktokFinalBlackSimilarityValue) tiktokFinalBlackSimilarityValue.textContent = tiktokFinalKeyingSettings.blackSimilarity.toFixed(3);
  if (tiktokFinalBlackBlendValue) tiktokFinalBlackBlendValue.textContent = tiktokFinalKeyingSettings.blackBlend.toFixed(3);
};

const readTikTokFinalKeyingFromInputs = () => {
  tiktokFinalKeyingSettings = normalizeTikTokFinalKeyingSettings({
    greenSimilarity: tiktokFinalGreenSimilarityInput?.value,
    greenBlend: tiktokFinalGreenBlendInput?.value,
    blackSimilarity: tiktokFinalBlackSimilarityInput?.value,
    blackBlend: tiktokFinalBlackBlendInput?.value
  });
  persistTikTokFinalKeyingSettings();
  syncTikTokFinalKeyingInputs();
  scheduleTikTokFinalKeyPreviewRender();
  return { ...tiktokFinalKeyingSettings };
};

const resetTikTokFinalKeyingSettings = ({ silent = false } = {}) => {
  tiktokFinalKeyingSettings = { ...TIKTOK_FINAL_KEYING_DEFAULTS };
  persistTikTokFinalKeyingSettings();
  syncTikTokFinalKeyingInputs();
  scheduleTikTokFinalKeyPreviewRender();
  if (!silent) {
    setTikTokFinalStatus('Step 8 keying reset to defaults.');
    scheduleSave();
  }
};

const setTikTokFinalKeyPreviewStatus = (text, isError = false) => {
  if (!tiktokFinalKeyPreviewStatus) return;
  tiktokFinalKeyPreviewStatus.textContent = text;
  tiktokFinalKeyPreviewStatus.style.color = isError ? '#ff7a7a' : '#97a0b9';
};

const calcKeyedAlpha = (r, g, b, keyR, keyG, keyB, similarity, blend) => {
  const dr = r - keyR;
  const dg = g - keyG;
  const db = b - keyB;
  const dist = Math.sqrt(dr * dr + dg * dg + db * db) / 441.6729559300637;
  if (dist <= similarity) return 0;
  if (blend > 0 && dist < similarity + blend) {
    return Math.round(((dist - similarity) / blend) * 255);
  }
  return 255;
};

const renderTikTokFinalKeyPreview = () => {
  if (!tiktokFinalKeyPreviewCanvas) return;
  const ctx = tiktokFinalKeyPreviewCanvas.getContext('2d');
  if (!ctx) return;
  const canvasW = tiktokFinalKeyPreviewCanvas.width || 378;
  const canvasH = tiktokFinalKeyPreviewCanvas.height || 672;
  ctx.clearRect(0, 0, canvasW, canvasH);
  ctx.fillStyle = '#00ff00';
  ctx.fillRect(0, 0, canvasW, canvasH);
  if (!tiktokFinalKeyPreviewImage) {
    setTikTokFinalKeyPreviewStatus('No green-screen avatar image loaded yet.');
    return;
  }

  const img = tiktokFinalKeyPreviewImage;
  const scale = Math.min(canvasW / Math.max(1, img.width), canvasH / Math.max(1, img.height));
  const drawW = Math.max(1, Math.round(img.width * scale));
  const drawH = Math.max(1, Math.round(img.height * scale));
  const drawX = Math.round((canvasW - drawW) / 2);
  const drawY = Math.round((canvasH - drawH) / 2);

  const offscreen = document.createElement('canvas');
  offscreen.width = drawW;
  offscreen.height = drawH;
  const offCtx = offscreen.getContext('2d', { willReadFrequently: true });
  if (!offCtx) {
    setTikTokFinalKeyPreviewStatus('Preview context unavailable.', true);
    return;
  }
  offCtx.drawImage(img, 0, 0, drawW, drawH);
  const imageData = offCtx.getImageData(0, 0, drawW, drawH);
  const data = imageData.data;
  const k = normalizeTikTokFinalKeyingSettings(tiktokFinalKeyingSettings);
  for (let i = 0; i < data.length; i += 4) {
    const r = data[i];
    const g = data[i + 1];
    const b = data[i + 2];
    const alphaGreen = calcKeyedAlpha(r, g, b, 0, 255, 0, k.greenSimilarity, k.greenBlend);
    const alphaBlack = calcKeyedAlpha(r, g, b, 0, 0, 0, k.blackSimilarity, k.blackBlend);
    data[i + 3] = Math.min(data[i + 3], alphaGreen, alphaBlack);
  }
  offCtx.putImageData(imageData, 0, 0);
  ctx.drawImage(offscreen, drawX, drawY);
  setTikTokFinalKeyPreviewStatus('Live key preview ready. Drag sliders, then run final output.');
};

const scheduleTikTokFinalKeyPreviewRender = () => {
  if (!tiktokFinalKeyPreviewCanvas) return;
  if (tiktokFinalKeyPreviewRenderRaf) cancelAnimationFrame(tiktokFinalKeyPreviewRenderRaf);
  tiktokFinalKeyPreviewRenderRaf = requestAnimationFrame(() => {
    tiktokFinalKeyPreviewRenderRaf = 0;
    renderTikTokFinalKeyPreview();
  });
};

const getTikTokFinalKeyPreviewSource = async () => {
  const fromAssets = String(tiktokAvatarAssets?.greenUrl || '').trim();
  if (fromAssets) return fromAssets;
  const fromActiveAvatar = await ensureAvatarGreenScreenUrl();
  if (fromActiveAvatar) return fromActiveAvatar;
  return '';
};

const refreshTikTokFinalKeyPreviewSource = async () => {
  if (!tiktokFinalKeyPreviewCanvas) return;
  const requestToken = Date.now();
  tiktokFinalKeyPreviewRequestToken = requestToken;
  setTikTokFinalKeyPreviewStatus('Loading green-screen preview image...');
  try {
    const src = await getTikTokFinalKeyPreviewSource();
    if (tiktokFinalKeyPreviewRequestToken !== requestToken) return;
    if (!src) {
      tiktokFinalKeyPreviewImage = null;
      tiktokFinalKeyPreviewSourceUrl = '';
      scheduleTikTokFinalKeyPreviewRender();
      setTikTokFinalKeyPreviewStatus('No green-screen avatar image found. Compress avatar assets in Step 7.', true);
      return;
    }
    if (src === tiktokFinalKeyPreviewSourceUrl && tiktokFinalKeyPreviewImage) {
      scheduleTikTokFinalKeyPreviewRender();
      return;
    }
    const img = new Image();
    img.decoding = 'async';
    img.onload = () => {
      if (tiktokFinalKeyPreviewRequestToken !== requestToken) return;
      tiktokFinalKeyPreviewImage = img;
      tiktokFinalKeyPreviewSourceUrl = src;
      scheduleTikTokFinalKeyPreviewRender();
    };
    img.onerror = () => {
      if (tiktokFinalKeyPreviewRequestToken !== requestToken) return;
      tiktokFinalKeyPreviewImage = null;
      tiktokFinalKeyPreviewSourceUrl = '';
      scheduleTikTokFinalKeyPreviewRender();
      setTikTokFinalKeyPreviewStatus('Could not load green-screen preview image.', true);
    };
    img.src = `${src}${String(src).includes('?') ? '&' : '?'}v=${Date.now()}`;
  } catch (_err) {
    if (tiktokFinalKeyPreviewRequestToken !== requestToken) return;
    tiktokFinalKeyPreviewImage = null;
    tiktokFinalKeyPreviewSourceUrl = '';
    scheduleTikTokFinalKeyPreviewRender();
    setTikTokFinalKeyPreviewStatus('Could not load key preview source.', true);
  }
};

