const hydrateObjectImage = (img) => {
  if (!img) return null;
  const localPath = img.localPath || img.path || '';
  const uploadedUrl = img.uploadedUrl || img.value || '';
  const preview =
    img.preview ||
    (localPath ? `file://${localPath}` : '') ||
    uploadedUrl ||
    img.thumbData ||
    '';
  return {
    type: img.type || (uploadedUrl ? 'url' : 'file'),
    path: localPath,
    localPath,
    name: img.name || '',
    label: img.label || img.name || uploadedUrl || '',
    mime: img.mime || '',
    uploadedUrl,
    value: uploadedUrl,
    thumbData: img.thumbData || '',
    preview
  };
};

