const renderAvatarSelectPreview = () => {
  if (!avatarSelectPreview) return;
  avatarSelectPreview.innerHTML = '';
  if (!activeAvatarName) {
    avatarSelectPreview.textContent = '';
    return;
  }
  const avatar = avatars.find((a) => a.name === activeAvatarName);
  if (!avatar) return;
  if (avatar.profile?.uploadedUrl || avatar.profile?.localPath || avatar.profile?.path) {
    const img = document.createElement('img');
    img.src = getAvatarEntryDisplayUrl(avatar.profile);
    img.style.width = '48px';
    img.style.height = '48px';
    img.style.objectFit = 'cover';
    img.style.borderRadius = '8px';
    img.style.border = '1px solid var(--border)';
    avatarSelectPreview.appendChild(img);
  }
  const name = document.createElement('div');
  name.className = 'small';
  const metaParts = [];
  if (avatar.age) metaParts.push(`age ${avatar.age}`);
  if (avatar.gender) metaParts.push(avatar.gender);
  name.textContent = metaParts.length ? `${activeAvatarName} (${metaParts.join(', ')})` : activeAvatarName;
  avatarSelectPreview.appendChild(name);
};

const renderObjectSelectPreview = () => {
  if (!objectSelectPreviewEls.length) return;
  objectSelectPreviewEls.forEach((previewEl) => {
    previewEl.innerHTML = '';
    if (!activeObjectName) {
      previewEl.textContent = '';
      return;
    }
    const obj = objects.find((o) => o.name === activeObjectName);
    if (!obj) return;
    const previewUrl = getObjectPreviewUrl(obj);
    if (previewUrl) {
      const img = document.createElement('img');
      img.src = previewUrl;
      img.style.width = '48px';
      img.style.height = '48px';
      img.style.objectFit = 'cover';
      img.style.borderRadius = '8px';
      img.style.border = '1px solid var(--border)';
      previewEl.appendChild(img);
    }
    const name = document.createElement('div');
    name.className = 'small';
    name.textContent = obj.description ? `${obj.name} — ${obj.description}` : obj.name;
    previewEl.appendChild(name);
  });
};

const getActiveAvatar = () => avatars.find((a) => a.name === activeAvatarName);
const getActiveObject = () => objects.find((o) => o.name === activeObjectName);

const getObjectImageDisplayUrl = (img) => {
  if (!img) return '';
  if (img.uploadedUrl) return img.uploadedUrl;
  if (img.preview) return img.preview;
  if (img.localPath || img.path) return `file://${img.localPath || img.path}`;
  if (img.thumbData) return img.thumbData;
  if (img.value) return img.value;
  return '';
};

const getObjectPreviewUrl = (obj) => {
  if (!obj) return '';
  const preferred = obj.environmentImage || obj.baseImage;
  if (preferred) {
    return getObjectImageDisplayUrl(preferred);
  }
  const first = (obj.images || []).find((img) => img.uploadedUrl || img.localPath || img.path || img.thumbData);
  if (!first) return '';
  return getObjectImageDisplayUrl(first);
};

const getActiveObjectFrameSource = () => {
  const obj = getActiveObject();
  if (!obj) return null;
  const preferred = obj.environmentImage || obj.baseImage;
  const first = preferred || (obj.images || []).find((img) => img.uploadedUrl || img.localPath || img.path || img.thumbData);
  if (!first) return null;
  const localPath = first.localPath || first.path || '';
  const previewUrl = getObjectImageDisplayUrl(first);
  return {
    uploadedUrl: first.uploadedUrl || '',
    previewUrl,
    localPath,
    path: first.path || '',
    thumbData: first.thumbData || '',
    mime: first.mime || '',
    name: first.name || ''
  };
};

const isObjectVideoFrame = (src) => src?.origin === 'object';

const getObjectFrameUploadUrl = () => {
  const entry = videoSources.find((src) => isObjectVideoFrame(src));
  if (!entry) return '';
  return entry.uploadedUrl || (entry.type === 'url' ? entry.value : '');
};

const makeObjectVideoFrameEntry = (source, name) => {
  const label = name ? `Object: ${name}` : source?.uploadedUrl || '';
  if (source?.uploadedUrl) {
    return {
      type: 'url',
      value: source.uploadedUrl,
      uploadedUrl: source.uploadedUrl,
      label,
      name: name ? `${name} (object)` : '',
      preview: source.previewUrl || source.uploadedUrl || '',
      origin: 'object'
    };
  }
  if (source?.localPath || source?.path) {
    const local = source.localPath || source.path;
    return {
      type: 'file',
      path: local,
      localPath: local,
      uploadedUrl: '',
      value: '',
      label,
      name: source.name || (name ? `${name} (object)` : ''),
      preview: source.previewUrl || `file://${local}`,
      mime: source.mime || '',
      origin: 'object'
    };
  }
  if (source?.thumbData) {
    const parsed = parseDataUrl(source.thumbData);
    return {
      type: 'file',
      uploadedUrl: '',
      value: '',
      label,
      name: source.name || (name ? `${name} (object)` : ''),
      preview: source.previewUrl || source.thumbData,
      mime: source.mime || parsed?.mime || '',
      blob: parsed ? new Blob([parsed.bytes], { type: parsed.mime }) : null,
      origin: 'object'
    };
  }
  return {
    type: 'url',
    value: '',
    uploadedUrl: '',
    label,
    name: name ? `${name} (object)` : '',
    preview: source?.previewUrl || '',
    origin: 'object'
  };
};

const syncVideoFrameFromObject = () => {
  if (currentCreateView !== 'video') return;
  const frameSource = getActiveObjectFrameSource();
  if (activeObjectName && frameSource?.previewUrl) {
    const base = videoSources.filter((src) => !isObjectVideoFrame(src));
    videoSources = [...base, makeObjectVideoFrameEntry(frameSource, activeObjectName)];
    renderVideoImages();
    return;
  }
  if (videoSources.some(isObjectVideoFrame)) {
    videoSources = videoSources.filter((src) => !isObjectVideoFrame(src));
    renderVideoImages();
  }
};

const getAvatarLabel = () => {
  const avatar = getActiveAvatar();
  if (!avatar) return 'No avatar selected';
  const parts = [`Avatar "${avatar.name}"`];
  if (avatar.description) parts.push(avatar.description);
  if (avatar.gender) parts.push(`gender ${avatar.gender}`);
  if (avatar.age) parts.push(`age ${avatar.age}`);
  return parts.join(' — ');
};

const setAvatarStatus = (text, isError = false) => {
  if (!avatarStatus) return;
  avatarStatus.textContent = text;
  avatarStatus.style.color = isError ? '#ff7a7a' : '#97a0b9';
};

const updateAvatarStatusHint = () => {
  if (!avatarStatus) return;
  const name = (avatarNameInput?.value || '').trim();
  const hasAnyImage = avatarSources.length || !!avatarProfileSource;
  if (!name && !hasAnyImage) {
    setAvatarStatus('Add a name and at least one image to save.');
    return;
  }
  if (!name) {
    setAvatarStatus('Add an avatar name to save.');
    return;
  }
  if (!hasAnyImage) {
    setAvatarStatus('Add at least one avatar image to save.');
    return;
  }
  const count = avatarSources.length || 1;
  setAvatarStatus(`Ready to save "${name}" • ${count} image(s).`);
};

const getActiveAvatarClothes = () => {
  const avatar = getActiveAvatar();
  if (!avatar || !Array.isArray(avatar.clothes)) return [];
  return avatar.clothes.filter((c) => c.uploadedUrl);
};

const pickRandomClothes = () => {
  const clothes = getActiveAvatarClothes();
  if (!clothes.length) return '';
  const choice = clothes[Math.floor(Math.random() * clothes.length)];
  return choice?.uploadedUrl || '';
};

const renderClothesPreview = () => {
  if (!clothesPreview) return;
  clothesPreview.innerHTML = '';
  if (!activeAvatarName) {
    clothesPreview.textContent = 'Select an avatar to use clothes';
    return;
  }
  const clothes = getActiveAvatarClothes();
  if (!clothes.length) {
    clothesPreview.textContent = 'No clothes uploaded for this avatar.';
    return;
  }
  if (!clothesEnabled) {
    clothesPreview.textContent = 'Clothes disabled for this request.';
    return;
  }
  const chosenUrl = selectedClothesUrl || '';
  if (!chosenUrl) {
    clothesPreview.textContent = 'Random clothes will be picked each generation.';
    return;
  }
  const img = document.createElement('img');
  img.src = chosenUrl;
  img.alt = 'Selected clothes';
  img.style.width = '72px';
  img.style.height = '72px';
  img.style.objectFit = 'cover';
  img.style.borderRadius = '8px';
  img.style.border = '1px solid var(--border)';
  clothesPreview.appendChild(img);
  const label = document.createElement('div');
  label.className = 'small';
  label.textContent = 'Using this outfit';
  clothesPreview.appendChild(label);
};

const renderClothesPicker = () => {
  if (!clothesRow || !useClothesToggle || !clothesSelect || !clothesRefreshBtn || !clothesUploadBtn) return;
  const hasAvatar = !!activeAvatarName;
  clothesRow.classList.toggle('hidden', !hasAvatar);
  const clothes = getActiveAvatarClothes();
  const hasClothes = clothes.length > 0;

  useClothesToggle.disabled = !hasClothes;
  if (!hasClothes) {
    clothesEnabled = false;
    selectedClothesUrl = '';
  }
  if (hasAvatar && hasClothes && clothesEnabled) {
    useClothesToggle.checked = true;
  } else {
    useClothesToggle.checked = false;
  }

  clothesSelect.innerHTML = '';
  const baseOpt = document.createElement('option');
  baseOpt.value = '';
  baseOpt.textContent = hasClothes ? 'Random each generation' : 'No clothes available';
  clothesSelect.appendChild(baseOpt);
  clothes.forEach((c) => {
    const opt = document.createElement('option');
    opt.value = c.uploadedUrl;
    opt.textContent = c.label || c.name || c.uploadedUrl;
    clothesSelect.appendChild(opt);
  });

  const optionExists = clothes.some((c) => c.uploadedUrl === selectedClothesUrl);
  clothesSelect.value = optionExists ? selectedClothesUrl : '';
  clothesSelect.disabled = !hasClothes || !useClothesToggle.checked;
  clothesRefreshBtn.disabled = !hasClothes || !useClothesToggle.checked;
  clothesUploadBtn.disabled = !hasAvatar;

  renderClothesPreview();
};

const renderBatchProgress = () => {
  if (!batchProgressEl) return;
  batchProgressEl.innerHTML = '';
  if (!batchRunState.length) {
    return;
  }
  batchRunState.forEach((item, idx) => {
    const wrap = document.createElement('div');
    wrap.className = 'history-item';
    const top = document.createElement('div');
    top.className = 'history-top';
    const name = document.createElement('div');
    name.className = 'history-name';
    name.textContent = `${item.kind} #${idx + 1}`;
    const meta = document.createElement('div');
    meta.className = 'history-meta';
    meta.textContent = item.status || 'pending';
    top.appendChild(name);
    top.appendChild(meta);

    const body = document.createElement('div');
    body.className = 'small';
    body.textContent = item.title || item.prompt?.slice(0, 120) || '';

    wrap.appendChild(top);
    wrap.appendChild(body);
    batchProgressEl.appendChild(wrap);
  });
};

const renderBatchPlan = () => {
  if (!batchPlanList) return;
  batchPlanList.innerHTML = '';
  if (!batchPlan.length) {
    batchPlanList.innerHTML = '<div class="small">No batch plan yet.</div>';
    return;
  }
  const isStory = getBatchType() === 'story';
  batchPlan.forEach((item, idx) => {
    const wrap = document.createElement('div');
    wrap.className = 'history-item';
    const top = document.createElement('div');
    top.className = 'history-top';
    const name = document.createElement('div');
    name.className = 'history-name';
    name.textContent = `${item.kind} #${idx + 1}`;
    const meta = document.createElement('div');
    meta.className = 'history-meta';
    meta.textContent = item.title || item.prompt.slice(0, 80);
    top.appendChild(name);
    top.appendChild(meta);

    const promptLabel = document.createElement('div');
    promptLabel.className = 'small';
    promptLabel.textContent = 'Prompt:';
    const promptBox = document.createElement('textarea');
    promptBox.className = 'input';
    promptBox.value = item.prompt;
    promptBox.style.minHeight = '68px';
    promptBox.addEventListener('input', (e) => {
      item.prompt = e.target.value;
    });

    const actions = document.createElement('div');
    actions.className = 'history-actions';
    if (isStory) {
      const outfitRow = document.createElement('div');
      outfitRow.className = 'small';
      outfitRow.style.marginTop = '6px';
      if (item.outfit) {
        const parts = [];
        if (item.outfit.title) parts.push(item.outfit.title);
        if (item.outfit.desc) parts.push(item.outfit.desc);
        outfitRow.textContent = `Outfit: ${parts.join(' — ') || 'None'}`;
        if (item.outfit.imageUrl) {
          const img = document.createElement('img');
          img.src = item.outfit.imageUrl;
          img.style.width = '80px';
          img.style.height = '80px';
          img.style.objectFit = 'cover';
          img.style.borderRadius = '8px';
          img.style.border = '1px solid var(--border)';
          img.style.marginLeft = '8px';
          outfitRow.appendChild(img);
        }
      } else {
        outfitRow.textContent = 'Outfit: None';
      }
      const toggleBtn = document.createElement('button');
      toggleBtn.className = 'secondary';
      toggleBtn.textContent = item.useClothes ? 'Use clothes: ON' : 'Use clothes: OFF';
      toggleBtn.addEventListener('click', () => {
        item.useClothes = !item.useClothes;
        renderBatchPlan();
      });
      actions.appendChild(toggleBtn);
      wrap.appendChild(outfitRow);
    }

    wrap.appendChild(top);
    wrap.appendChild(promptLabel);
    wrap.appendChild(promptBox);
    wrap.appendChild(actions);
    batchPlanList.appendChild(wrap);
  });
};

const renderSavedBatches = () => {
  if (!batchSavedList) return;
  batchSavedList.innerHTML = '';
  if (!savedBatches.length) {
    batchSavedList.innerHTML = '<div class="small">No saved batches.</div>';
    return;
  }
  savedBatches.forEach((b, idx) => {
    const item = document.createElement('div');
    item.className = 'history-item';
    const top = document.createElement('div');
    top.className = 'history-top';
    const name = document.createElement('div');
    name.className = 'history-name';
    name.textContent = b.name;
    const meta = document.createElement('div');
    meta.className = 'history-meta';
    meta.textContent = new Date(b.updatedAt || b.createdAt || Date.now()).toLocaleString();
    top.appendChild(name);
    top.appendChild(meta);

    const body = document.createElement('div');
    body.className = 'small';
    body.textContent = `${(b.plan || []).length} item(s)`;

    const actions = document.createElement('div');
    actions.className = 'history-actions';
    const loadBtn = document.createElement('button');
    loadBtn.className = 'secondary';
    loadBtn.textContent = 'Load';
    loadBtn.addEventListener('click', () => {
      batchOutfits = Array.isArray(b.outfits) ? b.outfits.map((o) => ({ ...o })) : [];
      batchManualOutfits = !!b.manualOutfits;
      batchOutfitsEnabled = b.outfitsEnabled !== false;
      batchPlan = Array.isArray(b.plan) ? b.plan.map((p) => ({ ...p })) : [];
      batchOutfitsApproved = false;
      if (batchOutfits.length) {
        batchPlan.forEach((p) => {
          const match =
            p.outfit && batchOutfits.find((o) => o.desc === p.outfit.desc && o.title === p.outfit.title);
            p.outfit = match || batchOutfits[0];
        });
        batchOutfits.forEach((o) => {
          if (o.imageUrl && !o.thumbUrl) {
            createOutfitThumb(o).then(() => renderBatchOutfits());
          }
        });
      }
      renderBatchOutfits();
      renderBatchPlan();
      setStatus(`Loaded batch "${b.name}"`);
    });
    const deleteBtn = document.createElement('button');
    deleteBtn.className = 'secondary';
    deleteBtn.textContent = 'Delete';
    deleteBtn.addEventListener('click', () => {
      savedBatches.splice(idx, 1);
      persistBatches(savedBatches);
      renderSavedBatches();
    });
    actions.appendChild(loadBtn);
    actions.appendChild(deleteBtn);

    item.appendChild(top);
    item.appendChild(body);
    item.appendChild(actions);
    batchSavedList.appendChild(item);
  });
};

const renderBatchOutfits = () => {
  if (!batchOutfitList) return;
  if (batchOutfitToggle) {
    batchOutfitToggle.checked = batchOutfitsEnabled;
  }
  if (!batchOutfitsEnabled) {
    batchOutfitList.innerHTML = '<div class="small">Outfits disabled.</div>';
    if (batchOutfitStatus) batchOutfitStatus.textContent = 'Outfits are off';
    return;
  }
  const ensureDefaultOutfitFromClothes = () => {
    if (batchOutfits.length) return;
    const clothes = getActiveAvatarClothes();
    if (!clothes.length) return;
    const first = clothes[0];
    batchOutfits.push({
      title: 'Outfit 1',
      desc: '',
      useAvatarClothes: true,
      avatarClothesUrl: first.uploadedUrl,
      imageUrl: first.uploadedUrl
    });
    batchOutfitsApproved = false;
  };

  ensureDefaultOutfitFromClothes();
  batchOutfitList.innerHTML = '';
  if (!batchOutfits.length) {
    batchOutfitList.innerHTML = '<div class="small">No outfits yet.</div>';
    if (batchOutfitStatus) batchOutfitStatus.textContent = '';
    return;
  }
  batchOutfits.forEach((o, idx) => {
    const item = document.createElement('div');
    item.className = 'history-item';
    const top = document.createElement('div');
    top.className = 'history-top';
    const name = document.createElement('div');
    name.className = 'history-name';
    name.textContent = `Outfit ${idx + 1}`;
    top.appendChild(name);

    const body = document.createElement('div');
    body.className = 'small';

    const columns = document.createElement('div');
    columns.style.display = 'grid';
    columns.style.gridTemplateColumns = 'repeat(auto-fit,minmax(240px,1fr))';
    columns.style.gap = '14px';
    columns.style.marginTop = '8px';

    // Avatar clothes column
    const avatarCol = document.createElement('div');
    avatarCol.className = 'card';
    avatarCol.style.padding = '12px';
    avatarCol.style.cursor = 'pointer';
    avatarCol.style.opacity = o.useAvatarClothes ? '1' : '0.4';
    avatarCol.addEventListener('click', () => {
      o.useAvatarClothes = true;
      if (o.avatarClothesUrl) {
        o.imageUrl = o.avatarClothesUrl;
        o.thumbUrl = '';
      }
      batchManualOutfits = true;
      renderBatchOutfits();
      renderBatchPlan();
    });
    const avatarTitle = document.createElement('div');
    avatarTitle.className = 'small';
    avatarTitle.style.fontWeight = '600';
    avatarTitle.textContent = 'Use avatar clothes';
    avatarTitle.style.opacity = '1';
    const clothes = getActiveAvatarClothes();
    const clothesRow = document.createElement('div');
    clothesRow.className = 'small';
    if (clothes.length) {
      const select = document.createElement('select');
      select.className = 'input';
      select.style.maxWidth = '100%';
      const placeholder = document.createElement('option');
      placeholder.value = '';
      placeholder.textContent = 'Pick from avatar wardrobe...';
      select.appendChild(placeholder);
      clothes.forEach((c, i) => {
        const opt = document.createElement('option');
        opt.value = c.uploadedUrl;
        opt.textContent = c.label || c.name || `Clothes ${i + 1}`;
        select.appendChild(opt);
      });
      if (o.avatarClothesUrl) select.value = o.avatarClothesUrl;
      select.addEventListener('change', (e) => {
        const chosen = e.target.value;
        if (!chosen) return;
        o.useAvatarClothes = true;
        o.avatarClothesUrl = chosen;
        o.imageUrl = chosen;
        o.thumbUrl = '';
        o.statusText = 'Using avatar clothes image';
        batchManualOutfits = true;
        createOutfitThumb(o).then(() => renderBatchOutfits());
        renderBatchPlan();
      });
      clothesRow.appendChild(select);
    } else {
      clothesRow.textContent = 'No avatar clothes available';
    }
    const avatarSelectBtn = document.createElement('button');
    avatarSelectBtn.className = 'secondary';
    avatarSelectBtn.textContent = 'Use this outfit';
    avatarSelectBtn.disabled = !clothes.length;
    avatarSelectBtn.addEventListener('click', () => {
      if (!clothes.length) return;
      o.useAvatarClothes = true;
      if (o.avatarClothesUrl) {
        o.imageUrl = o.avatarClothesUrl;
        o.thumbUrl = '';
      }
      renderBatchOutfits();
      renderBatchPlan();
    });
    avatarCol.appendChild(avatarTitle);
    avatarCol.appendChild(clothesRow);
    avatarCol.appendChild(avatarSelectBtn);

    // Generated column
    const genCol = document.createElement('div');
    genCol.className = 'card';
    genCol.style.padding = '12px';
    genCol.style.cursor = 'pointer';
    genCol.style.opacity = o.useAvatarClothes ? '0.4' : '1';
    genCol.addEventListener('click', () => {
      o.useAvatarClothes = false;
      o.avatarClothesUrl = '';
      renderBatchOutfits();
      renderBatchPlan();
    });
    const genTitle = document.createElement('div');
    genTitle.className = 'small';
    genTitle.style.fontWeight = '600';
    genTitle.textContent = 'Generate with prompts';
    genTitle.style.opacity = '1';
    const previewRow = document.createElement('div');
    previewRow.className = 'small';
    previewRow.style.display = 'flex';
    previewRow.style.alignItems = 'center';
    previewRow.style.gap = '8px';
    if (o.imageUrl && !o.useAvatarClothes) {
      if (!o.thumbUrl) {
        createOutfitThumb(o).then(() => renderBatchOutfits());
      }
      const img = document.createElement('img');
      img.src = o.thumbUrl || o.imageUrl;
      img.loading = 'lazy';
      img.decoding = 'async';
      img.style.width = '140px';
      img.style.height = '140px';
      img.style.objectFit = 'cover';
      img.style.borderRadius = '10px';
      img.style.border = '1px solid var(--border)';
      img.style.cursor = 'pointer';
      img.title = 'Click to open full size';
      img.addEventListener('click', () => {
        if (o.imageUrl) window.open(o.imageUrl, '_blank', 'noopener');
      });
      previewRow.appendChild(img);
    } else {
      previewRow.textContent = 'No generated outfit yet';
    }
    const statusText = document.createElement('div');
    statusText.className = 'small';
    statusText.style.marginTop = '4px';
    statusText.style.color = '#97a0b9';
    statusText.textContent = o.statusText || '';
    const actions = document.createElement('div');
    actions.className = 'history-actions';
    const genBtn = document.createElement('button');
    genBtn.className = 'secondary';
    const hasImage = !!o.generatedImageUrl;
    genBtn.textContent = o.generating ? 'Generating...' : hasImage ? 'Regenerate outfit image' : 'Generate outfit image';
    genBtn.disabled = !!o.generating;
    genBtn.addEventListener('click', () => generateOutfitImage(idx));
    actions.appendChild(genBtn);
    if (o.lastPrompt) {
      const promptBlock = document.createElement('div');
      promptBlock.className = 'small';
      promptBlock.style.marginTop = '6px';
      promptBlock.textContent = `Sent to Nano Banana:\n${o.lastPrompt}`;
      genCol.appendChild(promptBlock);
    }
    genCol.appendChild(genTitle);
    genCol.appendChild(previewRow);
    genCol.appendChild(statusText);
    genCol.appendChild(actions);

    columns.appendChild(avatarCol);
    columns.appendChild(genCol);

    body.appendChild(columns);

    item.appendChild(top);
    item.appendChild(body);
    batchOutfitList.appendChild(item);
  });
if (batchOutfitStatus) {
  batchOutfitStatus.textContent = '';
  batchOutfitStatus.style.color = '#97a0b9';
}
};

const renderPresets = () => {
  if (presetSelect) {
    presetSelect.innerHTML = '';
    if (!presets.length) {
      const opt = document.createElement('option');
      opt.value = '';
      opt.textContent = 'No presets yet';
      presetSelect.appendChild(opt);
    } else {
      const noneOpt = document.createElement('option');
      noneOpt.value = '';
      noneOpt.textContent = 'No preset';
      presetSelect.appendChild(noneOpt);
      presets.forEach((p) => {
        const opt = document.createElement('option');
        opt.value = p.name;
        opt.textContent = p.name;
        presetSelect.appendChild(opt);
      });
    }
  }

  if (selectedPresetChips) {
    selectedPresetChips.innerHTML = '';
    if (!selectedPresetNames.length) {
      const empty = document.createElement('div');
      empty.className = 'small';
      empty.textContent = 'No prompts selected.';
      selectedPresetChips.appendChild(empty);
    } else {
      selectedPresetNames.forEach((name) => {
        const chip = document.createElement('div');
        chip.className = 'history-item';
        chip.style.padding = '6px 10px';
        chip.style.display = 'inline-flex';
        chip.style.alignItems = 'center';
        chip.style.gap = '8px';
        const label = document.createElement('div');
        label.textContent = name;
        const removeBtn = document.createElement('button');
        removeBtn.className = 'secondary';
        removeBtn.textContent = '×';
        removeBtn.addEventListener('click', () => {
          selectedPresetNames = selectedPresetNames.filter((n) => n !== name);
          renderPresets();
        });
        chip.appendChild(label);
        chip.appendChild(removeBtn);
        selectedPresetChips.appendChild(chip);
      });
    }
  }

  if (presetPickerList) {
    presetPickerList.innerHTML = '';
    if (!presets.length) {
      presetPickerList.innerHTML = '<div class="small">No presets yet. Add some in Prompts tab.</div>';
    } else {
      presets.forEach((p) => {
        const item = document.createElement('div');
        item.className = 'history-item';
        const top = document.createElement('div');
        top.className = 'history-top';
        const name = document.createElement('div');
        name.className = 'history-name';
        name.textContent = p.name;
        const meta = document.createElement('div');
        meta.className = 'history-meta';
        meta.textContent = `${(p.text || '').slice(0, 80)}${p.text && p.text.length > 80 ? '…' : ''}`;
        top.appendChild(name);
        top.appendChild(meta);

        const actions = document.createElement('div');
        actions.className = 'history-actions';
        const addBtn = document.createElement('button');
        const already = selectedPresetNames.includes(p.name);
        addBtn.className = 'secondary';
        addBtn.textContent = already ? 'Added' : '+';
        addBtn.disabled = already;
        addBtn.addEventListener('click', () => {
          if (!selectedPresetNames.includes(p.name)) {
            selectedPresetNames = [...selectedPresetNames, p.name];
            setStatus(`Preset${selectedPresetNames.length === 1 ? '' : 's'} selected: ${selectedPresetNames.join(', ')}`);
            renderPresets();
            if (presetPickerWrap) presetPickerWrap.classList.add('hidden');
          }
        });
        actions.appendChild(addBtn);

        item.appendChild(top);
        item.appendChild(actions);
        presetPickerList.appendChild(item);
      });
    }
  }

  if (presetList) {
    presetList.innerHTML = '';
    if (!presets.length) {
      presetList.innerHTML = '<div class="small">No presets yet.</div>';
    } else {
      presets.forEach((p) => {
        const item = document.createElement('div');
        item.className = 'history-item';
        const top = document.createElement('div');
        top.className = 'history-top';
        const name = document.createElement('div');
        name.className = 'history-name';
        name.textContent = p.name;
        const meta = document.createElement('div');
        meta.className = 'history-meta';
        meta.textContent = `${(p.text || '').slice(0, 80)}${p.text && p.text.length > 80 ? '…' : ''}`;
        top.appendChild(name);
        top.appendChild(meta);
        const body = document.createElement('div');
        body.className = 'small';
        body.textContent = p.text || '';
        const actions = document.createElement('div');
        actions.className = 'history-actions';
        const editBtn = document.createElement('button');
        editBtn.className = 'secondary';
        editBtn.textContent = 'Edit';
        editBtn.addEventListener('click', () => {
          if (presetNameInput) presetNameInput.value = p.name;
          if (presetTextInput) presetTextInput.value = p.text || '';
          setStatus(`Editing preset "${p.name}"`);
        });
        const deleteBtn = document.createElement('button');
        deleteBtn.className = 'secondary';
        deleteBtn.textContent = 'Delete';
        deleteBtn.addEventListener('click', () => {
          const idx = presets.findIndex((x) => x.name === p.name);
          if (idx >= 0) {
            presets.splice(idx, 1);
            persistPresets(presets);
            selectedPresetNames = selectedPresetNames.filter((n) => n !== p.name);
            renderPresets();
            setStatus(`Deleted preset "${p.name}"`);
          }
        });
        actions.appendChild(editBtn);
        actions.appendChild(deleteBtn);
        item.appendChild(top);
        item.appendChild(body);
        item.appendChild(actions);
        presetList.appendChild(item);
      });
    }
  }
};

