const normalizeKieProgressPercent = (state = '', info = {}) => {
  const rawCandidates = [
    info?.progress,
    info?.progressPct,
    info?.progress_percent,
    info?.percent
  ];
  for (const raw of rawCandidates) {
    const num = Number(raw);
    if (!Number.isFinite(num)) continue;
    const scaled = num <= 1 ? num * 100 : num;
    if (scaled >= 0) return Math.max(0, Math.min(100, Math.round(scaled)));
  }
  const s = String(state || '').toLowerCase();
  if (s === 'success') return 100;
  if (s === 'generating') return 72;
  if (s === 'queuing') return 32;
  if (s === 'waiting') return 18;
  if (s === 'fail') return 100;
  return 0;
};

const formatKieRelativeMs = (value) => {
  const ms = Number(value);
  if (!Number.isFinite(ms) || ms <= 0) return '';
  const seconds = Math.round(ms / 1000);
  if (seconds < 60) return `${seconds}s`;
  const minutes = Math.floor(seconds / 60);
  const remSec = seconds % 60;
  if (minutes < 60) return remSec ? `${minutes}m ${remSec}s` : `${minutes}m`;
  const hours = Math.floor(minutes / 60);
  const remMin = minutes % 60;
  return remMin ? `${hours}h ${remMin}m` : `${hours}h`;
};

const formatKieSceneStatus = (state = '', info = {}) => {
  const s = String(state || '').toLowerCase();
  const queuePos = Number(info?.waitNum ?? info?.queueNum ?? info?.queue_pos);
  const failCode = String(info?.failCode || '').trim();
  const failMsg = String(info?.failMsg || '').trim();
  const createTime = Number(info?.createTime || 0);
  const updateTime = Number(info?.updateTime || 0);
  const elapsed = createTime > 0 ? formatKieRelativeMs(Date.now() - createTime) : '';
  const sinceUpdate = updateTime > 0 ? formatKieRelativeMs(Date.now() - updateTime) : '';
  if (s === 'waiting' || s === 'queuing') {
    const parts = [];
    parts.push(Number.isFinite(queuePos) && queuePos > 0 ? `Queued on Kie.ai (position ${queuePos})` : 'Queued on Kie.ai');
    if (elapsed) parts.push(`elapsed ${elapsed}`);
    if (sinceUpdate) parts.push(`last update ${sinceUpdate} ago`);
    return parts.join(' • ');
  }
  if (s === 'generating') {
    const pct = normalizeKieProgressPercent(s, info);
    const parts = [`Generating on Kie.ai (${pct}%)`];
    if (elapsed) parts.push(`elapsed ${elapsed}`);
    return parts.join(' • ');
  }
  if (s === 'success') {
    const parts = ['Completed on Kie.ai'];
    if (elapsed) parts.push(`elapsed ${elapsed}`);
    return parts.join(' • ');
  }
  if (s === 'fail') {
    if (failCode && failMsg) return `Kie failed (${failCode}): ${failMsg}`;
    if (failCode) return `Kie failed (${failCode})`;
    if (failMsg) return failMsg;
    return 'Kie.ai reported failed';
  }
  return s ? `Kie.ai state: ${s}` : 'Kie.ai pending';
};

