const normalizeTikTokZoomSettings = (raw = {}) => {
  const enabled = raw.enabled !== false;
  const durationSec = clampCaptionOverlayValue(raw.durationSec, 0.3, 4.0, TIKTOK_ZOOM_DEFAULTS.durationSec);
  const startScale = clampCaptionOverlayValue(raw.startScale, 1.0, 1.6, TIKTOK_ZOOM_DEFAULTS.startScale);
  const endScale = clampCaptionOverlayValue(raw.endScale, 1.0, 1.6, TIKTOK_ZOOM_DEFAULTS.endScale);
  const easingRaw = String(raw.easing || TIKTOK_ZOOM_DEFAULTS.easing).trim().toLowerCase();
  const easing = easingRaw === 'linear' ? 'linear' : 'easeOut';
  return {
    enabled,
    durationSec: Number(durationSec.toFixed(2)),
    startScale: Number(startScale.toFixed(2)),
    endScale: Number(endScale.toFixed(2)),
    easing
  };
};

