const resolveAutoIntroMaskInputSource = () => {
  const scenes = Array.isArray(tiktokStoryboard?.scenes) ? tiktokStoryboard.scenes : [];
  if (!scenes.length) return null;
  const selectedScene = scenes[0] || null;
  if (!selectedScene) return null;

  const activeAvatar = getActiveAvatar();
  const avatarGreenUrl =
    String(activeAvatar?.compressed_green_url || '').trim() ||
    String(tiktokAvatarAssets?.greenUrl || '').trim() ||
    String(getAvatarEntryDisplayUrl(activeAvatar?.greenScreen?.[0]) || '').trim();

  const sceneVideoCandidates = [
    String(fileUrlToPath(selectedScene?.avatar_talk_local_path || '') || '').trim(),
    String(selectedScene?.avatar_talk_url || '').trim()
  ].filter(Boolean);
  const sceneGreenCandidates = [
    String(fileUrlToPath(selectedScene?.avatar_talk_green_local_path || '') || '').trim(),
    String(selectedScene?.avatar_talk_green_url || '').trim(),
    String(fileUrlToPath(selectedScene?.avatar_green_local_path || '') || '').trim(),
    String(selectedScene?.avatar_green_url || '').trim()
  ].filter(Boolean);
  const picked = [...sceneVideoCandidates, ...sceneGreenCandidates, avatarGreenUrl]
    .find((v) => !!String(v || '').trim()) || '';
  if (!picked || isAudioUrl(picked)) return null;

  const sourceLabel = sceneVideoCandidates.includes(picked)
    ? `Step 7 Scene 1 output${selectedScene?.id ? ` (${selectedScene.id})` : ''}`
    : sceneGreenCandidates.includes(picked)
    ? `Scene 1 green-screen fallback${selectedScene?.id ? ` (${selectedScene.id})` : ''}`
    : 'Avatar green-screen asset';
  return { path: picked, label: sourceLabel };
};

const syncAutoIntroMaskInputSource = () => {
  const resolved = resolveAutoIntroMaskInputSource();
  if (!resolved) {
    setTikTokCaptionIntroMaskInputPreviewPath('');
    return;
  }
  const currentLabel = String(tiktokCaptionIntroMaskInputLabel?.textContent || '').trim();
  const nextLabelText = `Mask input source: ${resolved.label}`;
  if (String(tiktokCaptionIntroMaskInputPath || '').trim() === String(resolved.path || '').trim() && currentLabel === nextLabelText) {
    return;
  }
  setTikTokCaptionIntroMaskInputPreviewPath(resolved.path, resolved.label);
};

