const applyState = (state) => {
  modelInput.value = state.model || 'nano-banana-pro';
  aspectRatioSelect.value = state.aspect_ratio || 'auto';
  resolutionSelect.value = state.resolution || '1K';
  formatSelect.value = state.output_format || 'png';
  if (imageBatchSizeInput) imageBatchSizeInput.value = String(normalizeImageBatchSize(state.image_batch_size));
  promptInput.value = state.prompt || '';
  imageSources = [];
  (state.images || []).forEach((img) => {
    const hasPath = !!(img.localPath || img.path);
    if (hasPath) {
      const local = img.localPath || img.path;
      imageSources.push({
        type: 'file',
        value: img.value,
        uploadedUrl: img.uploadedUrl || '',
        label: img.label,
        path: local,
        localPath: local,
        name: img.name,
        preview: `file://${local}`,
        originalType: 'file',
        mime: img.mime || ''
      });
    } else if (img.value || img.uploadedUrl) {
      imageSources.push({
        type: 'file',
        uploadedUrl: img.uploadedUrl || img.value || '',
        label: img.label || img.value || img.uploadedUrl,
        path: '',
        localPath: '',
        name: img.name || '',
        originalType: 'file'
      });
    }
  });
  activeAvatarName = state.avatar || '';
  if (avatarSelect) {
    avatarSelect.value = activeAvatarName;
  }
  activeObjectName = state.object || '';
  if (activeObjectName && !getActiveObject()) {
    activeObjectName = '';
  }
  syncObjectSelects();
  resetClothesSelection(useClothesToggle?.checked ?? false);
  renderImages();
  renderAvatarOptions();
  renderAvatarSelectPreview();
  renderObjectOptions();
  const obj = getActiveObject();
  setObjectEnvStatus(obj?.environmentImage ? 'Environment image ready' : '');
  renderClothesPicker();
  setCreateView(currentCreateView || 'chooser');
};

