const log = (message) => {
  const time = new Date().toLocaleTimeString();
  if (logsEl) {
    logsEl.textContent = `[${time}] ${message}\n${logsEl.textContent}`.slice(0, 8000);
  }
  console.log(`[ui-log] ${message}`);
  if (window.electronAPI?.sendLog) {
    window.electronAPI.sendLog('log', message);
  }
};

const copyTextToClipboardSafe = async (text = '') => {
  const value = String(text || '').trim();
  if (!value) return false;
  try {
    if (navigator.clipboard?.writeText) {
      await navigator.clipboard.writeText(value);
      return true;
    }
    const ta = document.createElement('textarea');
    ta.value = value;
    ta.setAttribute('readonly', '');
    ta.style.position = 'fixed';
    ta.style.left = '-9999px';
    ta.style.top = '0';
    document.body.appendChild(ta);
    ta.select();
    const ok = document.execCommand('copy');
    document.body.removeChild(ta);
    return !!ok;
  } catch (_err) {
    return false;
  }
};

const showToast = (text, isError = false, label = 'Status') => {
  if (!toastContainer) return;
  const message = String(text || '').trim();
  if (!message) return;
  const now = Date.now();
  const key = `${label}|${isError ? 'err' : 'ok'}|${message}`;
  const seenAt = recentToasts.get(key) || 0;
  if (now - seenAt < 1500) return;
  if (now - lastToastAt < 180) return;
  lastToastAt = now;
  recentToasts.set(key, now);
  if (recentToasts.size > 180) {
    const cutoff = now - 60000;
    for (const [k, t] of recentToasts.entries()) {
      if (t < cutoff) recentToasts.delete(k);
    }
  }

  const toast = document.createElement('div');
  toast.className = `toast${isError ? ' error' : ''}`;
  const labelEl = document.createElement('div');
  labelEl.className = 'toast-label';
  labelEl.textContent = label;
  const messageEl = document.createElement('div');
  messageEl.className = 'toast-message';
  messageEl.textContent = message;
  toast.appendChild(labelEl);
  toast.appendChild(messageEl);
  toastContainer.appendChild(toast);
  requestAnimationFrame(() => toast.classList.add('show'));

  while (toastContainer.children.length > 6) {
    toastContainer.removeChild(toastContainer.firstElementChild);
  }

  const life = isError ? 5000 : 2800;
  setTimeout(() => {
    toast.classList.remove('show');
    setTimeout(() => {
      if (toast.parentNode === toastContainer) toastContainer.removeChild(toast);
    }, 180);
  }, life);
};

const setStatus = (text, isError = false) => {
  const message = String(text || '').trim();
  const isIdleState = !message || /^idle\.?$/i.test(message);
  if (statusPill) {
    statusPill.textContent = isIdleState ? '' : message;
    statusPill.classList.toggle('error', !isIdleState && isError);
    statusPill.classList.toggle('hidden', isIdleState);
  }
  if (!isIdleState) {
    showToast(message, isError, 'App');
  }
};

const formatKieError = (code, message = '') => {
  const base = `Error ${code}: ${message || 'Unknown error'}`;
  if (Number(code) >= 500) {
    return `${base} (ensure image URLs are direct, public http(s) links)`;
  }
  return base;
};

const setButtonSaving = (spinnerEl, saving) => {
  if (!spinnerEl) return;
  spinnerEl.classList.toggle('active', !!saving);
};

const draftPrompt = () => {
  const mode = promptModeSelect?.value || 'general';
  const tone = (promptToneInput?.value || '').trim();
  const setup = (promptSetupInput?.value || '').trim();
  if (!setup) {
    setStatus('Add an initial setup first', true);
    return;
  }
  const ratio = aspectRatioSelect?.value || 'auto';
  const res = resolutionSelect?.value || '1K';
  const avatarTag = mode === 'avatar' && activeAvatarName ? ` using avatar "${activeAvatarName}"` : '';
  const toneTag = tone ? ` in a ${tone} style` : '';
  const draft = `Create a high-quality image${avatarTag}. Subject: ${setup}. Aspect ratio ${ratio}, resolution ${res}.${toneTag ? ` Tone: ${toneTag.replace('in a ', '')}.` : ''} Focus on realism, coherent lighting, and clean composition.`;
  promptInput.value = draft;
  setStatus('Drafted prompt. Edit as needed.');
  scheduleSave();
};
const setActiveSaveDisplay = () => {
  if (!activeSaveName) {
    activeSaveDisplay.textContent = 'No save active';
    return;
  }
  const suffix = activeSaveIsSession ? ' (session)' : '';
  activeSaveDisplay.textContent = `Save: ${activeSaveName}${suffix}`;
};

const getBatchType = () => (batchTypeSelect?.value || 'story');

const updateBatchModeUI = () => {
  const isStory = getBatchType() === 'story';
  if (batchStoryThemeWrap) batchStoryThemeWrap.classList.toggle('hidden', !isStory);
  if (batchStoryCountWrap) batchStoryCountWrap.classList.toggle('hidden', !isStory);
  if (batchModeWrap) batchModeWrap.classList.toggle('hidden', !isStory);
  if (batchDiffWrap) batchDiffWrap.classList.toggle('hidden', isStory);
  if (batchObjectWrap) batchObjectWrap.classList.toggle('hidden', isStory);
  if (batchOutfitSection) batchOutfitSection.classList.toggle('hidden', !isStory);
  if (batchCarouselLabel) {
    batchCarouselLabel.textContent = isStory ? 'Carousel images (1-7)' : 'Variations (1-7)';
  }
  if (!isStory) {
    if (batchUseClothes) batchUseClothes.checked = false;
    if (batchOutfitToggle) batchOutfitToggle.checked = false;
    batchOutfitsEnabled = false;
  }
  if (batchUseClothes) batchUseClothes.disabled = !isStory;
  if (batchOutfitToggle) batchOutfitToggle.disabled = !isStory;
  if (avatarRow) {
    avatarRow.classList.toggle('hidden', currentCreateView === 'batch' && !isStory);
  }
  if (clothesRow) {
    clothesRow.classList.toggle('hidden', currentCreateView === 'batch' && !isStory);
  }
};

const setCreateView = (view) => {
  const normalized = ['chooser', 'image', 'video', 'batch', 'tiktok'].includes(view) ? view : 'image';
  currentCreateView = normalized;
  if (normalized) {
    localStorage.setItem(LAST_CREATE_VIEW_KEY, normalized);
  }
  if (createChooser) createChooser.classList.toggle('hidden', normalized !== 'chooser');
  if (imageView) imageView.classList.toggle('hidden', normalized !== 'image');
  if (videoView) videoView.classList.toggle('hidden', normalized !== 'video');
  if (batchView) batchView.classList.toggle('hidden', normalized !== 'batch');
  if (tiktokView) tiktokView.classList.toggle('hidden', normalized !== 'tiktok');
  if (builderShared) builderShared.classList.toggle('hidden', !(normalized === 'image' || normalized === 'batch'));
  if (builderImageTab) builderImageTab.classList.toggle('active', normalized === 'image');
  if (builderVideoTab) builderVideoTab.classList.toggle('active', normalized === 'video');
  if (builderBatchTab) builderBatchTab.classList.toggle('active', normalized === 'batch');
  if (builderTikTokTab) builderTikTokTab.classList.toggle('active', normalized === 'tiktok');
  if (normalized === 'video') syncVideoFrameFromObject();
  if (normalized === 'batch') updateBatchModeUI();
  if (normalized === 'tiktok') {
    fetchElevenlabsVoices({ silent: true, force: true });
    syncLibraryKeyToInput();
    tiktokStickyTargets = collectTikTokStickyTargets();
  }
  updateTaskVisibility();
  scheduleTikTokStickyStepUpdate();
};

const getCreatorTitle = (mode, explicitTitle = '') => {
  if (explicitTitle) return explicitTitle;
  if (mode === 'avatar' && activeAvatarName) return `Edit avatar "${activeAvatarName}"`;
  if (mode === 'object' && activeObjectName) return `Edit object "${activeObjectName}"`;
  return mode === 'avatar' ? 'Create new avatar' : 'Create new object';
};

let creatorPanelCloseCooldownUntil = 0;
let objectFileDialogOpen = false;
let objectFileDialogResetTimer = null;
const suppressCreatorPanelClose = (ms = 1200) => {
  creatorPanelCloseCooldownUntil = Math.max(creatorPanelCloseCooldownUntil, Date.now() + ms);
};
const creatorPanelCloseBlocked = () =>
  objectFileDialogOpen || Date.now() < creatorPanelCloseCooldownUntil;

const armObjectFileDialog = () => {
  objectFileDialogOpen = true;
  if (objectFileDialogResetTimer) clearTimeout(objectFileDialogResetTimer);
  objectFileDialogResetTimer = setTimeout(() => {
    objectFileDialogOpen = false;
  }, 30000);
};

const clearObjectFileDialog = () => {
  objectFileDialogOpen = false;
  if (objectFileDialogResetTimer) clearTimeout(objectFileDialogResetTimer);
  objectFileDialogResetTimer = null;
};

window.addEventListener('focus', () => {
  if (!objectFileDialogOpen) return;
  clearObjectFileDialog();
  suppressCreatorPanelClose(800);
});

const openCreatorPanel = (mode, { title = '' } = {}) => {
  if (!creatorPanel) return;
  if (avatarView) avatarView.classList.toggle('hidden', mode !== 'avatar');
  if (objectView) objectView.classList.toggle('hidden', mode !== 'object');
  if (creatorPanelTitle) creatorPanelTitle.textContent = getCreatorTitle(mode, title);
  creatorPanel.classList.add('show');
  document.body.classList.add('panel-open');
};

const closeCreatorPanel = () => {
  if (!creatorPanel) return;
  if (creatorPanelCloseBlocked()) return;
  creatorPanel.classList.remove('show');
  document.body.classList.remove('panel-open');
};

const getActiveSaveType = () => {
  const record = findSaveByName(activeSaveName).save;
  if (record?.type) return record.type;
  if (currentCreateView === 'batch') return 'batch';
  if (currentCreateView === 'video') return 'video';
  if (currentCreateView === 'tiktok') return 'tiktok';
  return 'image';
};

const buildCurrentStateByType = (type = 'image') => {
  if (type === 'batch') return serializeBatchState();
  if (type === 'video') return serializeVideoState();
  if (type === 'tiktok') return serializeTikTokState();
  return serializeState();
};

const persistLastActiveProject = () => {
  if (!activeSaveName) {
    localStorage.removeItem(LAST_ACTIVE_PROJECT_KEY);
    return;
  }
  const { save, session } = findSaveByName(activeSaveName);
  const type = save?.type || getActiveSaveType();
  const persisted = saves.find((s) => s.name === activeSaveName);
  const payload = {
    name: activeSaveName,
    type,
    session: false,
    updatedAt: Date.now()
  };
  if (!activeSaveIsSession || persisted || !session) {
    payload.session = false;
    try {
      localStorage.setItem(LAST_ACTIVE_PROJECT_KEY, JSON.stringify(payload));
    } catch (_err) {}
    return;
  }
  payload.session = true;
  try {
    payload.data = buildCurrentStateByType(type);
  } catch (_err) {
    payload.data = save?.data || {};
  }
  try {
    localStorage.setItem(LAST_ACTIVE_PROJECT_KEY, JSON.stringify(payload));
  } catch (_err) {}
};

const captureActiveSaveState = () => {
  if (!activeSaveName) return;
  const { save, session } = findSaveByName(activeSaveName);
  const isSession = session || activeSaveIsSession;
  const type = save?.type || getActiveSaveType();
  const sessionId = isSession ? save?.id || generateSessionId() : '';
  let data;
  try {
    if (type === 'batch') data = serializeBatchState();
    else if (type === 'video') data = serializeVideoState();
    else if (type === 'tiktok') data = serializeTikTokState();
    else data = serializeState();
  } catch (err) {
    return;
  }
  const record = {
    id: sessionId || undefined,
    name: activeSaveName,
    type,
    data,
    updatedAt: Date.now(),
    createdAt: save?.createdAt || Date.now(),
    session: !!isSession
  };
  if (isSession) {
    const idx = sessionId
      ? sessionSaves.findIndex((s) => s.id === sessionId)
      : sessionSaves.findIndex((s) => s.name === activeSaveName);
    if (idx >= 0) sessionSaves[idx] = record;
    else sessionSaves.unshift(record);
    persistSessionSaves(sessionSaves.slice(0, 50));
  } else {
    const idx = saves.findIndex((s) => s.name === activeSaveName);
    if (idx >= 0) saves[idx] = record;
    else saves.unshift(record);
    persistSaves(saves.slice(0, 50));
  }
  persistLastActiveProject();
};

const setActiveSave = (name, { session = false, skipCapture = false } = {}) => {
  if (!skipCapture && activeSaveName && activeSaveName !== name) {
    captureActiveSaveState();
  }
  activeSaveName = name || '';
  activeSaveIsSession = !!session;
  if (activeSaveName) {
    if (activeSaveIsSession) {
      sessionStorage.setItem(ACTIVE_SESSION_SAVE_KEY, activeSaveName);
      if (!saves.find((s) => s.name === activeSaveName)) {
        localStorage.removeItem(ACTIVE_SAVE_KEY);
      }
    } else {
      localStorage.setItem(ACTIVE_SAVE_KEY, activeSaveName);
      sessionStorage.removeItem(ACTIVE_SESSION_SAVE_KEY);
    }
  } else {
    localStorage.removeItem(ACTIVE_SAVE_KEY);
    sessionStorage.removeItem(ACTIVE_SESSION_SAVE_KEY);
  }
  setActiveSaveDisplay();
  if (activeSaveName) startAutosave();
  else stopAutosave();
  persistLastActiveProject();
  updateTaskVisibility();
  renderOpenTabs();
  log(`Active save set to "${activeSaveName || 'none'}"${activeSaveIsSession ? ' (session)' : ''}`);
  if (!activeSaveName && saveStatusText) {
    saveStatusText.textContent = 'Not saved yet';
    if (saveSpinner) saveSpinner.classList.remove('active');
    if (saveTick) saveTick.classList.remove('show');
  }
};

const scheduleSave = () => {
  if (!activeSaveName) {
    const inBuilder = activeView === 'builder';
    if (!inBuilder) return;
    createUntitledSave(getActiveSaveType(), { skipCapture: true });
    if (!activeSaveName) return;
  }
  if (saveDebounce) clearTimeout(saveDebounce);
  saveDebounce = setTimeout(() => {
    saveCurrentState(false);
    log(`Autosaved "${activeSaveName}" after change.`);
  }, 400);
};

const getUntitledBase = (type) => {
  if (type === 'batch') return `${UNTITLED_PREFIX} Batch`;
  if (type === 'video') return `${UNTITLED_PREFIX} Video`;
  if (type === 'tiktok') return `${UNTITLED_PREFIX} TikTok`;
  return `${UNTITLED_PREFIX} Image`;
};

const getUniqueUntitledName = (type) => {
  const base = getUntitledBase(type);
  const existing = new Set([...saves, ...sessionSaves].map((s) => s.name));
  if (!existing.has(base)) return base;
  let idx = 2;
  while (existing.has(`${base} ${idx}`)) idx += 1;
  return `${base} ${idx}`;
};

const createUntitledSave = (type, { skipCapture = false } = {}) => {
  const name = getUniqueUntitledName(type);
  let data = {};
  if (type === 'batch') data = serializeBatchState();
  else if (type === 'video') data = serializeVideoState();
  else if (type === 'tiktok') data = getEmptyTikTokState();
  else data = serializeState();
  const record = {
    id: generateSessionId(),
    name,
    type,
    data,
    updatedAt: Date.now(),
    createdAt: Date.now(),
    session: true
  };
  sessionSaves.unshift(record);
  persistSessionSaves(sessionSaves.slice(0, 50));
  setActiveSave(name, { session: true, skipCapture });
  renderSavesList();
  renderOpenTabs();
  return record;
};

const finalizeSaveActivation = (name) => {
  const trimmed = (name || '').trim();
  if (!trimmed) {
    setStatus('Save name required', true);
    return;
  }
  const existing = saves.find((s) => s.name === trimmed);
  setActiveSave(trimmed);
  if (existing) {
    if (existing.type === 'batch') {
      applyBatchState(existing.data || {});
      setActiveView('builder');
      setCreateView('batch');
    } else if (existing.type === 'video') {
      applyVideoState(existing.data || {});
      setActiveView('builder');
      setCreateView('video');
    } else if (existing.type === 'tiktok') {
      applyTikTokState(existing.data || {});
      setActiveView('builder');
      setCreateView('tiktok');
    } else {
      applyState(existing.data || {});
      setActiveView('builder');
      setCreateView('image');
    }
    setStatus(`Opened save "${trimmed}"`);
    log(`Opened save "${trimmed}"`);
  } else {
    saveCurrentState(false);
    setStatus(`Created save "${trimmed}"`);
    log(`Created save "${trimmed}"`);
  }
  renderSavesList();
  setActiveView('create');
  updateTaskVisibility();
};

const collectTikTokStickyTargets = () => {
  if (!tiktokView) return [];
  const sections = [...tiktokView.querySelectorAll('section.card')];
  return sections
    .map((section) => {
      const stepEl = section.querySelector('.step');
      const titleEl = section.querySelector('.section-title');
      const stepText = String(stepEl?.textContent || '').trim();
      const titleText = String(titleEl?.textContent || '').replace(/\s+/g, ' ').trim();
      if (!/^Step\s+\d+/i.test(stepText)) return null;
      return { section, stepText, titleText };
    })
    .filter(Boolean);
};

const shouldShowTikTokStickyStep = () =>
  !!tiktokStickyStep &&
  !!tiktokView &&
  activeView === 'builder' &&
  currentCreateView === 'tiktok' &&
  !tiktokView.classList.contains('hidden');

const getActiveTikTokPipelineRunState = () => {
  if (tiktokAvatarCompressRunning || tiktokAvatarGenerateRunning) {
    return { step: 7, label: 'Step 7 · Avatar processing' };
  }
  if (tiktokExportRunning) return { step: 6, label: 'Step 6 · Timeline + export' };
  if (tiktokClipSearching || tiktokAutoWorkflowRunning || tiktokAutoAllRunning)
    return { step: 5, label: 'Step 5 · Clip sourcing' };
  if (tiktokAudioGenerating || tiktokAutoAlignRunning) return { step: 4, label: 'Step 4 · Audio alignment' };
  if (tiktokStoryboardGenerating) return { step: 3, label: 'Step 3 · Storyboard' };
  if (tiktokGenerating) return { step: 2, label: 'Step 2 · Script drafts' };
  return null;
};

const retryTikTokPipelineStep = async () => {
  const active = getActiveTikTokPipelineRunState();
  if (active) {
    showToast('Stop the active step before retrying.', true, 'Pipeline');
    return;
  }
  const step = tiktokLastRunningStep || 1;
  if (step === 2) {
    focusTikTokStepAction({ actionSelector: '#tiktokGenerateBtn' }, false);
    await generateTikTokScripts();
    return;
  }
  if (step === 3) {
    focusTikTokStepAction({ actionSelector: '#tiktokStoryboardBtn' }, false);
    await generateTikTokStoryboard();
    return;
  }
  if (step === 4) {
    focusTikTokStepAction({ actionSelector: '#tiktokTtsBtn' }, false);
    if (!tiktokAudio) await generateTikTokTtsAudio();
    else await runLocalTikTokAlignment();
    return;
  }
  if (step === 5) {
    focusTikTokStepAction({ actionSelector: '#tiktokAutoAllBtn' }, false);
    await retryTikTokClipSourcing();
    return;
  }
  if (step === 6) {
    focusTikTokStepAction({ actionSelector: '#tiktokExportBtn' }, false);
    await exportTikTokTimeline();
    return;
  }
  if (step === 7) {
    focusTikTokStepAction({ actionSelector: '#tiktokAvatarGenerateBtn' }, false);
    await startAvatarVideoGenerationWorkflow();
    return;
  }
  showToast('No pipeline step available to retry yet.', true, 'Pipeline');
};

const stopActiveTikTokPipelineStep = async () => {
  const active = getActiveTikTokPipelineRunState();
  if (!active) {
    showToast('No active generation to stop.', true, 'Pipeline');
    return;
  }
  if (active.step === 2 && tiktokScriptsAbortController) {
    tiktokScriptsAbortController.abort();
    showToast('Stopping script generation…', false, 'Pipeline');
    return;
  }
  if (active.step === 3 && tiktokStoryboardAbortController) {
    tiktokStoryboardAbortController.abort();
    showToast('Stopping storyboard generation…', false, 'Pipeline');
    return;
  }
  if (active.step === 4) {
    if (tiktokTtsAbortController) {
      tiktokTtsAbortController.abort();
      showToast('Stopping TTS generation…', false, 'Pipeline');
      return;
    }
    if (tiktokAutoAlignRunning) {
      showToast('Alignment stop is not available mid-run yet.', true, 'Pipeline');
      return;
    }
  }
  if (active.step === 5) {
    tiktokStep5StopRequested = true;
    setTikTokClipStatus('Stop requested for Step 5.');
    showToast('Stopping clip sourcing…', false, 'Pipeline');
    return;
  }
  if (active.step === 6) {
    requestTikTokExportReset();
    showToast('Stopping export…', false, 'Pipeline');
    return;
  }
  if (active.step === 7) {
    requestTikTokAvatarProcessingCancel(false);
    showToast('Stopping avatar processing…', false, 'Pipeline');
  }
};

const pulseStickyTarget = (el) => {
  if (!el) return;
  el.classList.remove('sticky-step-focus');
  requestAnimationFrame(() => el.classList.add('sticky-step-focus'));
  setTimeout(() => {
    if (el.classList) el.classList.remove('sticky-step-focus');
  }, 1200);
};

const getTikTokStepStatuses = () => {
  const storyboardScenes = Array.isArray(tiktokStoryboard?.scenes) ? tiktokStoryboard.scenes : [];
  const requiredClipScenes = storyboardScenes.filter((s) => !s.avatar_reserved && !s.merge_with_prev);
  const sourcedScenes = requiredClipScenes.filter((s) => !!s.clip?.url);
  const avatarRequiredScenes = storyboardScenes.filter((s) => !!s?.id);
  const avatarCompletedScenes = avatarRequiredScenes.filter((s) => !!s.avatar_talk_url);
  const avatarEnabled = !!String(activeAvatarName || '').trim();
  const hasExport =
    !!(tiktokBasePreview?.getAttribute('src') || '').trim() ||
    /^exported to /i.test((tiktokExportStatus?.textContent || '').trim());
  return [
    {
      complete: !!(tiktokIdeaInput?.value || '').trim(),
      need: 'Add an idea prompt in Step 1.',
      done: 'Idea prompt is set.',
      actionSelector: '#tiktokIdeaInput',
      completeSelector: '#tiktokIdeaInput'
    },
    {
      complete: Array.isArray(tiktokScripts) && tiktokScripts.length > 0,
      need: 'Generate scripts in Step 1/2.',
      done: `Generated ${tiktokScripts.length} script${tiktokScripts.length === 1 ? '' : 's'}.`,
      actionSelector: '#tiktokGenerateBtn',
      completeSelector: '#tiktokScriptList'
    },
    {
      complete: storyboardScenes.length > 0,
      need: 'Generate storyboard in Step 3.',
      done: `Storyboard ready with ${storyboardScenes.length} scene${storyboardScenes.length === 1 ? '' : 's'}.`,
      actionSelector: '#tiktokStoryboardBtn',
      completeSelector: '#tiktokStoryboardOutput'
    },
    {
      complete: !!tiktokAudio,
      need: 'Generate TTS audio in Step 4.',
      done: `TTS ready${tiktokAlignment ? ' + alignment applied' : ''}.`,
      actionSelector: '#tiktokTtsBtn',
      completeSelector: '#tiktokAudioPlayer'
    },
    {
      complete: requiredClipScenes.length > 0 && sourcedScenes.length === requiredClipScenes.length,
      need: 'Source clips for each scene in Step 5.',
      done: `Clips sourced: ${sourcedScenes.length}/${requiredClipScenes.length}.`,
      actionSelector: '#tiktokAutoAllBtn',
      completeSelector: '#tiktokClipList'
    },
    {
      complete: hasExport,
      need: 'Export the final video in Step 6.',
      done: hasExport ? (tiktokExportStatus?.textContent || 'Export completed.') : 'Export completed.',
      actionSelector: '#tiktokExportBtn',
      completeSelector: '#tiktokBasePreview'
    },
    {
      complete: !avatarEnabled || (avatarRequiredScenes.length > 0 && avatarCompletedScenes.length === avatarRequiredScenes.length),
      need: avatarEnabled ? 'Run avatar processing in Step 7.' : 'Optional: select an avatar to enable Step 7.',
      done: avatarEnabled
        ? `Avatar clips ready: ${avatarCompletedScenes.length}/${avatarRequiredScenes.length}.`
        : 'Step 7 skipped (no avatar selected).',
      actionSelector: '#tiktokAvatarGenerateBtn',
      completeSelector: '#tiktokAvatarClipsList'
    }
  ];
};

const focusTikTokStepAction = (status = {}, completed = false) => {
  const selector = completed ? status.completeSelector || status.actionSelector : status.actionSelector;
  const targetEl = selector ? document.querySelector(selector) : null;
  if (!targetEl) return;
  const section = targetEl.closest('section.card') || targetEl;
  section.scrollIntoView({ behavior: 'smooth', block: 'start' });
  pulseStickyTarget(section);
  setTimeout(() => {
    try {
      targetEl.focus({ preventScroll: true });
    } catch (_err) {}
  }, 120);
};

const updateTikTokStickyStepNow = () => {
  if (
    !tiktokStickyStep ||
    !tiktokStickyStepTitle ||
    !tiktokStickyStepSubtitle ||
    !tiktokStickyProgressFill ||
    !tiktokStickyDots ||
    !tiktokStickyRemaining
  ) {
    return;
  }
  if (!shouldShowTikTokStickyStep()) {
    tiktokStickyStep.classList.add('hidden');
    tiktokStickyActiveIdx = -1;
    return;
  }
  if (!tiktokStickyTargets.length) {
    tiktokStickyTargets = collectTikTokStickyTargets();
  }
  if (!tiktokStickyTargets.length) {
    tiktokStickyStep.classList.add('hidden');
    tiktokStickyActiveIdx = -1;
    return;
  }
  const topLine = 108;
  let active = tiktokStickyTargets[0];
  tiktokStickyTargets.forEach((target) => {
    const rect = target.section.getBoundingClientRect();
    if (rect.top <= topLine) active = target;
  });
  const activeIndex = Math.max(0, tiktokStickyTargets.indexOf(active));
  const totalSteps = tiktokStickyTargets.length;
  const statuses = getTikTokStepStatuses();
  tiktokStickyStepTitle.textContent = active.stepText;
  tiktokStickyStepSubtitle.textContent = active.titleText || '';
  if (tiktokStickyDots.children.length !== totalSteps) {
    tiktokStickyDots.innerHTML = '';
    for (let i = 0; i < totalSteps; i += 1) {
      const dot = document.createElement('span');
      dot.className = 'sticky-dot';
      dot.setAttribute('role', 'button');
      dot.tabIndex = 0;
      tiktokStickyDots.appendChild(dot);
    }
  }
  [...tiktokStickyDots.children].forEach((dot, idx) => {
    const status = statuses[idx] || { complete: false, need: 'Complete this step.', done: '' };
    const completed = !!status.complete;
    dot.classList.toggle('complete', completed);
    dot.classList.toggle('incomplete', !completed);
    dot.classList.toggle('active', idx === activeIndex);
    dot.title = completed ? status.done || 'Step completed.' : status.need || 'Step not completed.';
    dot.onclick = () => {
      focusTikTokStepAction(status, completed);
      showToast(completed ? status.done || 'Completed step.' : status.need || 'Complete this step.', false, completed ? 'Completed' : 'Next step');
    };
    dot.onkeydown = (e) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        dot.click();
      }
    };
  });
  let contiguousComplete = -1;
  for (let i = 0; i < statuses.length; i += 1) {
    if (statuses[i]?.complete) contiguousComplete = i;
    else break;
  }
  const progressPct =
    totalSteps > 1 && contiguousComplete >= 0
      ? (contiguousComplete / (totalSteps - 1)) * 100
      : 0;
  tiktokStickyProgressFill.style.width = `${Math.max(0, Math.min(100, progressPct))}%`;
  const remaining = statuses.filter((s) => !s.complete).length;
  tiktokStickyRemaining.textContent =
    remaining === 0 ? 'All steps completed' : `${remaining} step${remaining === 1 ? '' : 's'} left`;
  tiktokStickyRemaining.style.color = remaining === 0 ? '#7ef29d' : '#97a0b9';
  const activeRun = getActiveTikTokPipelineRunState();
  if (activeRun) {
    tiktokLastRunningStep = activeRun.step;
  }
  if (tiktokStickyRunStatus) {
    tiktokStickyRunStatus.textContent = activeRun
      ? `Generating: ${activeRun.label}`
      : tiktokLastRunningStep
      ? `Last active: Step ${tiktokLastRunningStep}`
      : 'No active generation.';
    tiktokStickyRunStatus.style.color = activeRun ? '#7ec0f2' : '#97a0b9';
  }
  if (tiktokStickyStopBtn) {
    tiktokStickyStopBtn.disabled = !activeRun;
  }
  if (tiktokStickyRetryBtn) {
    tiktokStickyRetryBtn.disabled = !!activeRun || !tiktokLastRunningStep;
  }
  if (activeIndex !== tiktokStickyActiveIdx) {
    tiktokStickyActiveIdx = activeIndex;
    tiktokStickyStep.classList.remove('updating');
    requestAnimationFrame(() => tiktokStickyStep.classList.add('updating'));
    setTimeout(() => tiktokStickyStep?.classList.remove('updating'), 460);
  }
  tiktokStickyStep.classList.remove('hidden');
};

const scheduleTikTokStickyStepUpdate = () => {
  if (tiktokStickyStepRaf) return;
  tiktokStickyStepRaf = requestAnimationFrame(() => {
    tiktokStickyStepRaf = 0;
    updateTikTokStickyStepNow();
  });
};

