  if (createChooser) createChooser.classList.toggle('hidden', !inCreate);
  if (imageView) imageView.classList.toggle('hidden', !(visible && inBuilder && currentCreateView === 'image'));
  if (videoView) videoView.classList.toggle('hidden', !(visible && inBuilder && currentCreateView === 'video'));
