const loadAvatarIntoBuilder = (name, { resetName = true } = {}) => {
  const existing = avatars.find((a) => a.name === name);
  if (!existing) return;
  activeAvatarName = name;
  avatarSources = (existing.images || []).map((img) => ({
    type: 'file',
    path: img.localPath || img.path || '',
    localPath: img.localPath || img.path || '',
    name: img.name || '',
    label: img.label || '',
    mime: img.mime || '',
    uploadedUrl: img.uploadedUrl || '',
    preview: getAvatarEntryDisplayUrl(img)
  }));
  renderAvatarImages();
  if (avatarAgeInput) avatarAgeInput.value = existing.age || '';
  if (avatarGenderInput) avatarGenderInput.value = existing.gender || '';
  avatarProfileSource = null;
  if (existing.profile) {
    avatarProfileSource = {
      ...existing.profile,
      path: existing.profile.localPath || existing.profile.path || '',
      localPath: existing.profile.localPath || existing.profile.path || '',
      uploadedUrl: existing.profile.uploadedUrl || ''
    };
    if (avatarProfilePreview) {
      avatarProfilePreview.textContent = '';
      const img = document.createElement('img');
      img.src = getAvatarEntryDisplayUrl(existing.profile);
      img.style.width = '64px';
      img.style.height = '64px';
      img.style.objectFit = 'cover';
      img.style.borderRadius = '8px';
      img.style.border = '1px solid var(--border)';
      avatarProfilePreview.appendChild(img);
    }
  } else if (avatarProfilePreview) {
    avatarProfilePreview.textContent = 'No profile image.';
  }
  if (avatarDescInput) avatarDescInput.value = existing.description || '';
  clothesSources = (existing.clothes || []).map((img) => ({
    type: 'file',
    path: img.localPath || img.path || '',
    localPath: img.localPath || img.path || '',
    name: img.name || '',
    label: img.label || '',
    mime: img.mime || '',
    uploadedUrl: img.uploadedUrl || '',
    preview: getAvatarEntryDisplayUrl(img)
  }));
  renderClothesImages();
  greenScreenSources = (existing.greenScreen || []).map((img) => ({
    type: 'file',
    path: img.localPath || img.path || '',
    localPath: img.localPath || img.path || '',
    name: img.name || '',
    label: img.label || '',
    mime: img.mime || '',
    uploadedUrl: img.uploadedUrl || '',
    preview: getAvatarEntryDisplayUrl(img)
  }));
  renderGreenScreenImages();
  if (avatarNameInput && resetName) avatarNameInput.value = name;
  updateAvatarStatusHint();
};

const syncStageProgressBar = () => {
  if (!progressBar || !stagesEl) return;
  const stageNodes = stageOrder
    .map((key) => stagesEl.querySelector(`[data-stage="${key}"]`))
    .filter(Boolean);
  if (!stageNodes.length) {
    progressBar.style.width = '0%';
    return;
  }
  let progressUnits = 0;
  for (const node of stageNodes) {
    if (node.classList.contains('done')) {
      progressUnits += 1;
      continue;
    }
    if (node.classList.contains('active') || node.classList.contains('error')) {
      progressUnits += 0.55;
    }
    break;
  }
  const width = Math.max(0, Math.min(100, (progressUnits / stageNodes.length) * 100));
  progressBar.style.width = `${width}%`;
};

const resetStages = () => {
  const stages = stagesEl.querySelectorAll('.stage');
  stages.forEach((s) => s.classList.remove('active', 'done', 'error'));
  syncStageProgressBar();
};

const setStageState = (stageKey, state) => {
  const el = stagesEl.querySelector(`[data-stage="${stageKey}"]`);
  if (!el) return;
  el.classList.remove('active', 'done', 'error');
  if (state === 'active') el.classList.add('active');
  if (state === 'done') el.classList.add('done');
  if (state === 'error') el.classList.add('error');
  syncStageProgressBar();
};

const markStageDoneThrough = (stageKey) => {
  const targetIndex = stageOrder.indexOf(stageKey);
  stageOrder.forEach((key, idx) => {
    if (idx <= targetIndex) {
      setStageState(key, 'done');
    }
  });
  if (targetIndex + 1 < stageOrder.length) {
    setStageState(stageOrder[targetIndex + 1], 'active');
  }
};

