let activeView = 'auth';
let viewLockUntil = 0;
let viewLockTarget = '';

const restoreLastView = () => {
  const lastView = localStorage.getItem(LAST_VIEW_KEY);
  const lastCreate = localStorage.getItem(LAST_CREATE_VIEW_KEY);
  if (lastCreate) currentCreateView = lastCreate;
  if (lastView && views[lastView]) {
    setActiveView(lastView, { force: true, reason: 'restore' });
    if (lastView === 'builder') {
      setCreateView(currentCreateView || 'image');
    }
    return true;
  }
  return false;
};

const readStoredWindowScrollY = () => {
  const raw = localStorage.getItem(WINDOW_SCROLL_Y_KEY);
  const parsed = Number(raw);
  if (!Number.isFinite(parsed) || parsed < 0) return 0;
  return Math.round(parsed);
};

const persistWindowScrollY = () => {
  if (windowScrollRestoreActive) return;
  const y = Math.max(0, Math.round(Number(window.scrollY ?? window.pageYOffset ?? 0) || 0));
  localStorage.setItem(WINDOW_SCROLL_Y_KEY, String(y));
};

const schedulePersistWindowScrollY = () => {
  if (windowScrollRestoreActive) return;
  if (windowScrollPersistTimer) clearTimeout(windowScrollPersistTimer);
  windowScrollPersistTimer = setTimeout(() => {
    windowScrollPersistTimer = null;
    persistWindowScrollY();
  }, 120);
};

const restoreWindowScrollY = ({ retries = 20, delayMs = 120 } = {}) => {
  const target = readStoredWindowScrollY();
  if (!target) return;
  windowScrollRestoreActive = true;
  let attempts = Math.max(1, Number(retries) || 1);
  const step = () => {
    const docEl = document.documentElement;
    const maxTop = Math.max(0, Number((docEl?.scrollHeight || 0) - (window.innerHeight || 0)));
    const nextTop = Math.max(0, Math.min(target, maxTop));
    window.scrollTo({ top: nextTop, behavior: 'auto' });
    const current = Math.max(0, Math.round(Number(window.scrollY ?? window.pageYOffset ?? 0) || 0));
    attempts -= 1;
    if (Math.abs(current - nextTop) <= 2 || attempts <= 0) {
      windowScrollRestoreActive = false;
      persistWindowScrollY();
      return;
    }
    setTimeout(step, Math.max(40, Number(delayMs) || 120));
  };
  setTimeout(step, 0);
};

const setActiveView = (name, { force = false, reason = '' } = {}) => {
  console.log('[ui] setActiveView', name, 'activeSave:', activeSaveName, reason ? `reason=${reason}` : '');
  if (Date.now() < viewLockUntil && viewLockTarget && name !== viewLockTarget && !force) return;
  if (name === 'history' && Date.now() < viewLockUntil) return;
  if (!force && name === 'history' && activeView !== 'auth') {
    console.warn('[ui] blocked history switch');
    console.trace('[ui] history switch trace');
    log(`Blocked history switch. reason=${reason || 'unknown'}`);
    return;
  }
  const previousView = activeView;
  activeView = name;
  if (name && name !== 'auth') {
    localStorage.setItem(LAST_VIEW_KEY, name);
  }
  Object.entries(views).forEach(([key, el]) => {
    el.classList.toggle('active', key === activeView);
  });
  navButtons.forEach((btn) => {
    const view = btn.getAttribute('data-view');
    btn.classList.toggle('active', view === activeView);
  });
  if (activeView === 'builder') {
    renderTikTokSfxEvents();
    requestSfxTimelineRender();
  }
  if (activeView === 'activity') {
    if (previousView !== 'activity') {
      const hasWarmRows = activityRecords.length > 0;
      const now = Date.now();
      const isFresh =
        hasWarmRows &&
        activityFeedInitialized &&
        !activityLastLoadError &&
        activityLastSuccessfulLoadAt > 0 &&
        now - activityLastSuccessfulLoadAt <= ACTIVITY_AUTO_REFRESH_COOLDOWN_MS;
      if (!hasWarmRows) {
        activityFeedInitialized = false;
        activityLastLoadError = '';
      }
      activityForceProbeBlocked = false;
      if (hasWarmRows) {
        setActivityStatus(
          isFresh
            ? `Showing ${activityRecords.length} loaded record(s).`
            : `Showing ${activityRecords.length} loaded record(s). Refreshing latest activity...`
        );
      }
      if (activityViewEntryRefreshTimer) {
        clearTimeout(activityViewEntryRefreshTimer);
        activityViewEntryRefreshTimer = null;
      }
      activityViewEntryRefreshTimer = setTimeout(() => {
        activityViewEntryRefreshTimer = null;
        if (activeView !== 'activity') return;
        if (isFresh && hasWarmRows) return;
        ensureActivityFeedLoaded({ forceReconnect: false, source: 'view-enter' }).catch((err) => {
          const message = String(err?.message || '').trim();
          if (message) setActivityStatus(message, true);
        });
      }, 60);
    } else {
      ensureActivityFeedLoaded({ source: 'view-active' }).catch((err) => {
        const message = String(err?.message || '').trim();
        if (message) setActivityStatus(message, true);
      });
    }
    scheduleActivityScrollCheck();
  } else if (activityStartupRetryTimer) {
    clearActivityStartupRetry();
  }
  if (activeView !== 'activity' && activityLazyLoadObserver) {
    activityLazyLoadObserver.disconnect();
    activityLazyLoadObserver = null;
  }
  if (activeView !== 'activity' && activityViewEntryRefreshTimer) {
    clearTimeout(activityViewEntryRefreshTimer);
    activityViewEntryRefreshTimer = null;
  }
  if (builderTopBar) builderTopBar.classList.toggle('hidden', activeView !== 'builder');
  if (statusCard) statusCard.classList.toggle('hidden', activeView !== 'builder');
  if (resultsCard) resultsCard.classList.toggle('hidden', activeView !== 'builder');
  updateTaskVisibility();
};

const unlockApp = (fromLoad = false) => {
  console.log('[ui] unlockApp');
  setStatus('Idle');
  setKeyStatus(fromLoad ? 'Unlocked — loaded saved key.' : 'Unlocked — key in memory.');
  const restored = restoreLastView();
  if (!restored) {
    if (activeSaveName) {
      setActiveView('create');
    } else {
      setActiveView('history', { force: true, reason: 'unlock' });
      setStatus('Create or select a save to continue', true);
    }
  }
  setActiveSaveDisplay();
  startCreditPolling();
  scheduleActivitySessionPrewarm('unlock');
  updateTaskVisibility();
};

