const renderImages = () => {
  imageListEl.innerHTML = '';
  if (!imageSources.length) {
    imageListEl.innerHTML = '<div class="small">No images yet. Drop files/URLs or paste one above.</div>';
    return;
  }

  imageSources.forEach((src, idx) => {
    const chip = document.createElement('div');
    chip.className = 'image-chip';

    const imgSrc = src.preview || src.thumbData || (src.path ? `file://${src.path}` : src.value);
    if (imgSrc) {
      const img = document.createElement('img');
      img.src = imgSrc;
      img.alt = src.name || 'Local image';
      img.style.cursor = 'zoom-in';
      img.addEventListener('click', (e) => {
        e.preventDefault();
        if (previewSpinner) previewSpinner.style.display = 'inline-block';
        showPreviewImage(imgSrc);
      });
      chip.appendChild(img);
    }

    const meta = document.createElement('div');
    meta.className = 'chip-meta';

    const name = document.createElement('div');
    name.className = 'small chip-name';
    name.textContent = src.label || src.value || src.name || 'Image';

    const actions = document.createElement('div');
    actions.className = 'chip-actions';

    const type = document.createElement('span');
    type.className = 'type';
    type.textContent = src.type === 'url' ? 'URL' : 'Local';

    const removeBtn = document.createElement('button');
    removeBtn.textContent = 'Remove';
    removeBtn.addEventListener('click', () => {
      imageSources.splice(idx, 1);
      renderImages();
      scheduleSave();
    });

    actions.appendChild(type);
    actions.appendChild(removeBtn);
    meta.appendChild(name);
    meta.appendChild(actions);
    chip.appendChild(meta);

    imageListEl.appendChild(chip);
  });
};

