const renderObjectImages = () => {
  if (!objectImageList) return;
  objectImageList.innerHTML = '';
  if (!objectSources.length) {
    objectImageList.innerHTML = '<div class="small">No object images.</div>';
    return;
  }
  objectSources.forEach((src, idx) => {
    const chip = document.createElement('div');
    chip.className = 'image-chip';

    if (src.path) {
      src.preview = `file://${src.path}`;
    } else if (!src.preview && src.thumbData) {
      src.preview = src.thumbData;
    }
    const imgSrc = src.preview || src.thumbData || (src.path ? `file://${src.path}` : src.uploadedUrl || src.value);
    if (imgSrc) {
      const img = document.createElement('img');
      img.src = imgSrc;
      img.alt = src.name || 'Object image';
      img.style.cursor = 'pointer';
        img.title = 'Click to preview';
        img.addEventListener('click', () => {
          const fullSrc = src.uploadedUrl || (src.path ? `file://${src.path}` : src.value || imgSrc);
          if (previewImg && previewModal) {
            if (previewSpinner) previewSpinner.style.display = 'inline-block';
            showPreviewImage(fullSrc);
            if (previewImg) {
              previewImg.onload = () => {
                if (previewSpinner) previewSpinner.style.display = 'none';
                previewImg.style.opacity = '1';
              };
            }
          } else if (fullSrc) {
            window.open(fullSrc, '_blank', 'noopener');
          }
        });
      img.style.width = '160px';
      img.style.height = '120px';
      img.style.objectFit = 'cover';
      img.style.borderRadius = '10px';
      img.style.border = '1px solid var(--border)';
      img.style.background = 'rgba(255, 255, 255, 0.03)';
      img.style.display = 'block';
      img.style.margin = '0 auto';
      chip.appendChild(img);
    }

    const meta = document.createElement('div');
    meta.className = 'chip-meta';

    const left = document.createElement('div');
    left.style.flex = '1';
    left.className = 'small';
    left.textContent = src.label || src.value || src.name || 'Object image';

    const removeBtn = document.createElement('button');
    removeBtn.textContent = 'Remove';
    removeBtn.addEventListener('click', () => {
      objectSources.splice(idx, 1);
      renderObjectImages();
      scheduleObjectDraftSave();
    });

    meta.appendChild(left);
    meta.appendChild(removeBtn);
    chip.appendChild(meta);
    objectImageList.appendChild(chip);
  });
};

