const envPanelLogLine = (text = '') => {
  if (!envPanelLog) return;
  const stamp = new Date().toLocaleTimeString();
  envPanelLog.textContent = `${envPanelLog.textContent}${envPanelLog.textContent ? '\n' : ''}[${stamp}] ${text}`;
  envPanelLog.scrollTop = envPanelLog.scrollHeight;
};

const envSetStageState = (stageKey, state) => {
  if (!envPanelStages) return;
  const el = envPanelStages.querySelector(`[data-env-stage="${stageKey}"]`);
  if (!el) return;
  el.classList.remove('active', 'done', 'error');
  if (state === 'active') el.classList.add('active');
  if (state === 'done') el.classList.add('done');
  if (state === 'error') el.classList.add('error');
};

const envResetStages = () => {
  if (!envPanelStages) return;
  envPanelStages.querySelectorAll('.env-stage').forEach((s) => s.classList.remove('active', 'done', 'error'));
};

const envMarkDoneThrough = (stageKey) => {
  if (!envPanelStages) return;
  const order = ['prepare', 'submit', 'queue', 'generate', 'complete'];
  const idx = order.indexOf(stageKey);
  order.forEach((key, i) => {
    if (i <= idx) envSetStageState(key, 'done');
  });
  if (idx + 1 < order.length) envSetStageState(order[idx + 1], 'active');
};

const renderEnvPanelImage = (wrapEl, src, label) => {
  if (!wrapEl) return;
  wrapEl.innerHTML = '';
  if (!src) {
    wrapEl.innerHTML = `<div class="small">${label}</div>`;
    return;
  }
  const chip = document.createElement('div');
  chip.className = 'image-chip';
  const img = document.createElement('img');
  img.src = src;
  img.alt = label;
  chip.appendChild(img);
  wrapEl.appendChild(chip);
};

const openEnvPanel = ({ baseUrl = '' } = {}) => {
  if (!envPanel) return;
  envPanel.classList.add('show');
  envPanelOpen = true;
  envPanelLastState = '';
  if (envPanelStatus) envPanelStatus.textContent = 'Preparing...';
  if (envPanelTick) envPanelTick.classList.remove('show');
  if (envPanelLog) envPanelLog.textContent = '';
  envResetStages();
  envSetStageState('prepare', 'active');
  renderEnvPanelImage(envPanelBaseWrap, baseUrl, 'Base image');
  renderEnvPanelImage(envPanelResultWrap, '', 'Result will appear here.');
};

const closeEnvPanel = ({ auto = false } = {}) => {
  if (!envPanel) return;
  if (auto) {
    setTimeout(() => {
      envPanel.classList.remove('show');
      envPanelOpen = false;
    }, 600);
    return;
  }
  envPanel.classList.remove('show');
  envPanelOpen = false;
};

const applyEnvJobState = (state) => {
  if (!envPanelOpen) return;
  if (state && state !== envPanelLastState) {
    envPanelLastState = state;
    envPanelLogLine(`State update: ${state}`);
  }
  if (state === 'waiting' || state === 'queuing') {
    envMarkDoneThrough('submit');
    envSetStageState('queue', 'active');
    if (envPanelStatus) envPanelStatus.textContent = 'Queued...';
  } else if (state === 'generating') {
    envMarkDoneThrough('queue');
    envSetStageState('generate', 'active');
    if (envPanelStatus) envPanelStatus.textContent = 'Generating...';
  } else if (state === 'success') {
    envMarkDoneThrough('complete');
    if (envPanelStatus) envPanelStatus.textContent = 'Completed';
  } else if (state === 'fail') {
    envSetStageState('generate', 'error');
    if (envPanelStatus) envPanelStatus.textContent = 'Failed';
  }
};

