const loadObjectIntoBuilder = (name) => {
  const existing = objects.find((o) => o.name === name);
  if (!existing) return;
  activeObjectName = name;
  if (objectNameInput) objectNameInput.value = existing.name || '';
  if (objectDescInput) objectDescInput.value = existing.description || '';
  if (objectEnvPromptInput) objectEnvPromptInput.value = existing.environmentPrompt || '';
  objectBaseSource = hydrateObjectImage(existing.baseImage);
  objectEnvironmentSource = hydrateObjectImage(existing.environmentImage);
  objectSources = (existing.images || []).map((img) => ({
    type: img.type || (img.uploadedUrl ? 'url' : 'file'),
    path: img.localPath || img.path || '',
    localPath: img.localPath || img.path || '',
    name: img.name || '',
    label: img.label || img.name || img.uploadedUrl || '',
    mime: img.mime || '',
    uploadedUrl: img.uploadedUrl || '',
    value: img.uploadedUrl || '',
    preview: img.localPath ? `file://${img.localPath}` : img.uploadedUrl || img.thumbData || '',
    thumbData: img.thumbData || ''
  }));
  renderObjectBasePreview();
  renderObjectEnvironmentPreview();
  renderObjectImages();
  scheduleObjectDraftSave();
};

