if (tiktokSfxLocalLibraryList) {
  tiktokSfxLocalLibraryList.addEventListener('click', (event) => {
    const applyBtn = event.target instanceof Element ? event.target.closest('[data-sfx-local-apply]') : null;
    if (applyBtn) {
      const id = String(applyBtn.getAttribute('data-sfx-local-apply') || '').trim();
      if (!id) return;
      const row = applyBtn.closest('[data-sfx-local-row]');
      const input = row ? row.querySelector('[data-sfx-local-label-input]') : null;
      const raw = input instanceof HTMLInputElement ? input.value : '';
      updateTikTokSfxLocalLibraryLabels(id, raw);
      return;
    }
    const btn = event.target instanceof Element ? event.target.closest('[data-sfx-local-remove]') : null;
    if (!btn) return;
    const id = String(btn.getAttribute('data-sfx-local-remove') || '').trim();
    if (!id) return;
    tiktokSfxLocalLibrary = tiktokSfxLocalLibrary.filter((item) => String(item?.id || '') !== id);
    renderTikTokSfxLocalLibrary();
    scheduleSave();
  });
  tiktokSfxLocalLibraryList.addEventListener('change', (event) => {
    const input = event.target instanceof Element ? event.target.closest('[data-sfx-local-label-input]') : null;
    if (!(input instanceof HTMLInputElement)) return;
    const id = String(input.getAttribute('data-sfx-local-label-input') || '').trim();
    if (!id) return;
    updateTikTokSfxLocalLibraryLabels(id, input.value);
  });
  tiktokSfxLocalLibraryList.addEventListener('keydown', (event) => {
    const input = event.target instanceof Element ? event.target.closest('[data-sfx-local-label-input]') : null;
    if (!(input instanceof HTMLInputElement)) return;
    if (event.key !== 'Enter') return;
    event.preventDefault();
    const id = String(input.getAttribute('data-sfx-local-label-input') || '').trim();
    if (!id) return;
    updateTikTokSfxLocalLibraryLabels(id, input.value);
  });
}

