if (tiktokStoryboardCopyBtn) {
  tiktokStoryboardCopyBtn.addEventListener('click', async () => {
    if (!tiktokStoryboardOutput) return;
    const text = tiktokStoryboardOutput.value.trim();
    if (!text) return;
    try {
      if (navigator.clipboard?.writeText) {
        await navigator.clipboard.writeText(text);
      } else {
        tiktokStoryboardOutput.focus();
        tiktokStoryboardOutput.select();
        document.execCommand('copy');
      }
      setTikTokStoryboardStatus('Copied storyboard JSON.');
    } catch (_err) {
      setTikTokStoryboardStatus('Copy failed. Select and copy manually.', true);
    }
  });
}

