if (tiktokSfxSoundList) {
  tiktokSfxSoundList.addEventListener('click', (event) => {
    const fixBtn = event.target instanceof Element ? event.target.closest('[data-sfx-essential-fix="1"]') : null;
    if (fixBtn) {
      const key = String(fixBtn.getAttribute('data-sfx-essential-key') || '').trim();
      const query = String(fixBtn.getAttribute('data-sfx-essential-query') || '').trim();
      const label = String(fixBtn.getAttribute('data-sfx-essential-label') || '').trim();
      const timeSec = Number(fixBtn.getAttribute('data-sfx-essential-time') || 0);
      const ok = addStep11EssentialCueAtAnchor({ key, query, label, timeSec });
      if (ok) {
        showToast(`Added missing essential cue: ${label || key}`, false, 'Step 11');
        setTikTokSfxStatus('Added missing essential cue. Re-run render when ready.', false);
      }
      return;
    }
    const btn = event.target instanceof Element ? event.target.closest('.sfx-sound-play') : null;
    if (!btn) return;
    const idx = Number(btn.getAttribute('data-sfx-idx'));
    if (!Number.isFinite(idx) || idx < 0 || idx >= tiktokSfxEvents.length) return;
    playResolvedSfxCue(tiktokSfxEvents[idx], idx, 0)
      .then((ok) => {
        if (!ok) showToast('Could not resolve a real sound file for this cue. Check labels/library.', true, 'Step 11');
      })
      .catch(() => {
        showToast('Failed to play cue preview.', true, 'Step 11');
      });
  });
}

