const bindTimelineZoomHandle = ({
  handleEl = null,
  side = 'left',
  getZoom = () => 1,
  getScroller = () => null,
  setZoomAnchored = () => {},
  requestRender = () => {}
} = {}) => {
  if (!handleEl) return;
  const beginDrag = (startClientX = 0, endHook = () => {}) => {
    const startX = Number(startClientX || 0);
    const startZoom = Number(getZoom() || 1) || 1;
    const scroller = getScroller();
    const viewportWidth = Math.max(1, Number(scroller?.clientWidth || 0));
    const anchorTime = Math.max(
      0,
      Number((Number(scroller?.scrollLeft || 0) + viewportWidth * 0.5) / Math.max(1, 60 * startZoom))
    );
    const move = (clientX = startX) => {
      const dx = Number(clientX || 0) - startX;
      const inward = side === 'left' ? dx : -dx;
      const factor = Math.exp(inward / 180);
      setZoomAnchored(startZoom * factor, anchorTime);
      requestRender();
    };
    const finish = () => {
      endHook();
      scheduleSave();
    };
    return { move, finish };
  };

  handleEl.addEventListener('pointerdown', (event) => {
    event.preventDefault();
    event.stopPropagation();
    const drag = beginDrag(event.clientX, () => {
      handleEl.releasePointerCapture?.(event.pointerId);
      handleEl.removeEventListener('pointermove', onMove);
      handleEl.removeEventListener('pointerup', onUp);
      handleEl.removeEventListener('pointercancel', onUp);
    });
    const onMove = (ev) => {
      drag.move(ev.clientX);
    };
    const onUp = () => {
      drag.finish();
    };
    handleEl.setPointerCapture?.(event.pointerId);
    handleEl.addEventListener('pointermove', onMove);
    handleEl.addEventListener('pointerup', onUp, { once: true });
    handleEl.addEventListener('pointercancel', onUp, { once: true });
  });

  handleEl.addEventListener('mousedown', (event) => {
    event.preventDefault();
    event.stopPropagation();
    const drag = beginDrag(event.clientX, () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
    });
    const onMove = (ev) => {
      drag.move(ev.clientX);
    };
    const onUp = () => {
      drag.finish();
    };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp, { once: true });
  });

  handleEl.addEventListener(
    'touchstart',
    (event) => {
      const touch = event.touches?.[0];
      if (!touch) return;
      event.preventDefault();
      event.stopPropagation();
      const drag = beginDrag(touch.clientX, () => {
        window.removeEventListener('touchmove', onMove);
        window.removeEventListener('touchend', onUp);
        window.removeEventListener('touchcancel', onUp);
      });
      const onMove = (ev) => {
        const t = ev.touches?.[0];
        if (!t) return;
        drag.move(t.clientX);
      };
      const onUp = () => {
        drag.finish();
      };
      window.addEventListener('touchmove', onMove, { passive: true });
      window.addEventListener('touchend', onUp, { once: true });
      window.addEventListener('touchcancel', onUp, { once: true });
    },
    { passive: false }
  );
};

