if (window.electronAPI?.onTikTokExportProgress) {
  window.electronAPI.onTikTokExportProgress((data) => {
    if (!data || typeof data !== 'object') return;
    const runId = String(data.runId || '');
    if (!runId || !tiktokExportRunId || runId !== tiktokExportRunId) return;
    const tag = String(data.tag || data.phase || '').toLowerCase();
    const rawPct = Math.max(0, Math.min(100, Number(data.percent) || 0));
    const mappedPct =
      tag === 'base'
        ? rawPct <= 0
          ? 0
          : Math.max(1, Math.round(rawPct * 0.45))
        : tag === 'final'
        ? rawPct <= 0
          ? 45
          : Math.max(46, Math.round(45 + rawPct * 0.55))
        : rawPct;
    const phaseLabel = tag === 'base' ? 'Base Stitch' : tag === 'final' ? 'Final Render' : 'Render';
    const desc = String(data.message || '').trim() || 'Rendering timeline...';
    setStep6StitchBoard({
      visible: true,
      percent: mappedPct,
      phase: phaseLabel,
      desc
    });
    setTikTokFinalProgress(mappedPct);
  });
}

if (window.electronAPI?.onTikTokCaptionRenderProgress) {
  window.electronAPI.onTikTokCaptionRenderProgress((data) => {
    if (!data || typeof data !== 'object') return;
    if (!tiktokCaptionRenderRunning) return;
    const runId = String(data.runId || '');
    if (!runId || !tiktokCaptionRenderRunId || runId !== tiktokCaptionRenderRunId) return;
    const incoming = Math.max(0, Math.min(100, Number(data.percent) || 0));
    const next = Math.max(tiktokCaptionRenderProgressValue, incoming);
    const label = String(data.message || '').trim() || 'Rendering captions';
    setTikTokCaptionRenderProgress(next, label);
  });
}

if (window.electronAPI?.onTikTokZoomRenderProgress) {
  window.electronAPI.onTikTokZoomRenderProgress((data) => {
    if (!data || typeof data !== 'object') return;
    if (!tiktokZoomRenderRunning) return;
    const runId = String(data.runId || '');
    if (!runId || !tiktokZoomRenderRunId || runId !== tiktokZoomRenderRunId) return;
    const incoming = Math.max(0, Math.min(100, Number(data.percent) || 0));
    const next = Math.max(tiktokZoomProgressValue, incoming);
    const label = String(data.message || '').trim() || 'Rendering intro zoom';
    setTikTokZoomProgress(next, label);
  });
}

if (window.electronAPI?.onTikTokSfxProgress) {
  window.electronAPI.onTikTokSfxProgress((data) => {
    if (!data || typeof data !== 'object') return;
    if (!tiktokSfxRenderRunning) return;
    const runId = String(data.runId || '');
    if (!runId || !tiktokSfxRenderRunId || runId !== tiktokSfxRenderRunId) return;
    const incomingRaw = Number(data.percent);
    const hasProgress = Number.isFinite(incomingRaw);
    const incoming = hasProgress ? Math.max(0, Math.min(100, incomingRaw)) : tiktokSfxProgressValue;
    const next = hasProgress ? Math.max(tiktokSfxProgressValue, incoming) : tiktokSfxProgressValue;
    const label = String(data.message || '').trim() || 'Rendering SFX mix';
    const labelLower = label.toLowerCase();
    const traceStatus = String(data?.trace?.status || '').trim().toLowerCase();
    const stopLoadingFlash =
      labelLower.includes('preparing event synthesis') ||
      labelLower.includes('mixing base audio with sfx layer') ||
      labelLower.includes('rendering sfx mix') ||
      labelLower.includes('normalizing final audio loudness') ||
      labelLower.includes('completed');
    const startLoadingFlash =
      labelLower.includes('resolving') ||
      ['searching', 'queued', 'requesting', 'response', 'downloading', 'downloaded', 'cache-hit'].includes(traceStatus);
    if (stopLoadingFlash) setTikTokSfxTimelineDownloadFlash(false);
    else if (startLoadingFlash) setTikTokSfxTimelineDownloadFlash(true);
    setTikTokSfxProgress(next, label);
    if (data.trace && typeof data.trace === 'object') {
      applyTikTokSfxTrace(data.trace);
    }
  });
}

if (window.electronAPI?.onTikTokIntroMaskProgress) {
  window.electronAPI.onTikTokIntroMaskProgress((data) => {
    if (!data || typeof data !== 'object') return;
    if (!tiktokCaptionIntroMaskPreviewRunning) return;
    const runId = String(data.runId || '');
    if (!runId || !tiktokCaptionIntroMaskRunId || runId !== tiktokCaptionIntroMaskRunId) return;
    const incoming = Math.max(0, Math.min(100, Number(data.percent) || 0));
    const next = incoming;
    const label = String(data.message || '').trim() || 'Rendering intro mask';
    setTikTokCaptionIntroMaskProgress(next, label);
    if (label) setTikTokCaptionIntroMaskStatus(`Intro mask: ${label}`);
  });
}

