if (presetAddBtn) {
  presetAddBtn.addEventListener('click', () => {
    const name = (presetNameInput?.value || '').trim();
    const text = (presetTextInput?.value || '').trim();
    if (!name || !text) {
      setStatus('Preset name and text required', true);
      return;
    }
    const existingIdx = presets.findIndex((p) => p.name === name);
    const record = { name, text };
    if (existingIdx >= 0) {
      presets[existingIdx] = record;
    } else {
      presets.unshift(record);
    }
    persistPresets(presets.slice(0, 50));
    selectedPresetNames = Array.from(new Set([...selectedPresetNames, name]));
    renderPresets();
    setStatus(`Saved preset "${name}"`);
  });
}

if (presetDeleteBtn) {
  presetDeleteBtn.addEventListener('click', () => {
    const name = (presetSelect?.value || presetNameInput?.value || '').trim();
    if (!name) {
      setStatus('Select a preset to delete', true);
      return;
    }
    const idx = presets.findIndex((p) => p.name === name);
    if (idx >= 0) {
      presets.splice(idx, 1);
      persistPresets(presets);
      selectedPresetNames = selectedPresetNames.filter((n) => n !== name);
      renderPresets();
      setStatus(`Deleted preset "${name}"`);
    }
  });
}

