if (downloadSelectedBtn) {
  downloadSelectedBtn.addEventListener('click', async () => {
    const selectedImages = aggregateResults.filter((r) => r.selected === true && r.mediaType !== 'video');
    const hasVideos = aggregateResults.some((r) => r.mediaType === 'video');
    if (!selectedImages.length) {
      setStatus(
        hasVideos ? 'Select image results to download. Open videos individually.' : 'Select at least one image to download',
        true
      );
      return;
    }
    const prefix = sanitizeDownloadPrefix(downloadPrefixInput?.value || resultsDownloadPrefix);
    resultsDownloadPrefix = prefix;
    localStorage.setItem('nb_results_download_prefix', resultsDownloadPrefix);
    if (downloadPrefixInput) downloadPrefixInput.value = resultsDownloadPrefix;
    downloadSelectedBtn.disabled = true;
    let completed = 0;
    let failed = 0;
    const canSaveToFolder =
      !!window.electronAPI?.selectImageSaveTarget &&
      !!window.electronAPI?.getImageSequenceNextIndex &&
      !!window.electronAPI?.saveImageFile;
    if (canSaveToFolder) {
      const target = await resolveBulkSaveTarget(resultsDownloadPrefix);
      if (target?.canceled) {
        setStatus('Download cancelled', true);
        renderResults(aggregateResults);
        return;
      }
      if (target?.error || !target?.directoryPath) {
        setStatus(target?.error || 'Could not resolve save location.', true);
        renderResults(aggregateResults);
        return;
      }
      resultsDownloadPrefix = sanitizeDownloadPrefix(target.prefix || resultsDownloadPrefix);
      localStorage.setItem('nb_results_download_prefix', resultsDownloadPrefix);
      if (downloadPrefixInput) downloadPrefixInput.value = resultsDownloadPrefix;

      const startIndex = Math.max(0, Number(target.nextIndex) || 0);
      for (let i = 0; i < selectedImages.length; i += 1) {
        const item = selectedImages[i];
        const filename = `${resultsDownloadPrefix}_${startIndex + i}.webp`;
        try {
          const webpBlob = await fetchImageAsWebpBlob(item.url);
          const saveRes = await saveWebpBlobToDirectory({
            webpBlob,
            directoryPath: target.directoryPath,
            filename
          });
          if (saveRes?.success) {
            completed += 1;
          } else {
            failed += 1;
            log(`Save failed for ${filename}: ${saveRes?.error || 'Unknown error'}`);
          }
        } catch (err) {
          failed += 1;
          log(`WEBP conversion failed for ${item.url}: ${err.message}`);
        }
      }
      if (failed) {
        setStatus(`Saved ${completed} WEBP image(s) to ${target.directoryPath}; ${failed} failed.`, true);
      } else {
        setStatus(
          `Saved ${completed} WEBP image(s) to ${target.directoryPath} starting at ${resultsDownloadPrefix}_${startIndex}.webp`
        );
      }
    } else {
      for (let i = 0; i < selectedImages.length; i += 1) {
        const item = selectedImages[i];
        const filename = `${resultsDownloadPrefix}_${i + 1}.webp`;
        const ok = await downloadImageWithFilename({ url: item.url, filename });
        if (ok) completed += 1;
        else failed += 1;
      }
      if (failed) {
        setStatus(`Downloaded ${completed} WEBP image(s); ${failed} failed to convert.`, true);
      } else {
        setStatus(`Downloaded ${completed} WEBP image(s) with prefix "${resultsDownloadPrefix}"`);
      }
    }
    renderResults(aggregateResults);
  });
}

