if (activityScrapeLogCopyBtn) {
  activityScrapeLogCopyBtn.addEventListener('click', async () => {
    const text = getActivityScrapeLogText();
    let copied = false;
    try {
      if (navigator?.clipboard?.writeText) {
        await navigator.clipboard.writeText(text);
        copied = true;
      }
    } catch (_err) {}
    if (!copied) {
      try {
        const ta = document.createElement('textarea');
        ta.value = text;
        ta.setAttribute('readonly', 'readonly');
        ta.style.position = 'fixed';
        ta.style.opacity = '0';
        ta.style.pointerEvents = 'none';
        document.body.appendChild(ta);
        ta.select();
        copied = document.execCommand('copy');
        document.body.removeChild(ta);
      } catch (_err) {
        copied = false;
      }
    }
    if (copied) {
      setActivityStatus('Scrape logs copied to clipboard.');
      pushActivityScrapeLog('[Scrape] Copied scrape logs to clipboard.');
    } else {
      setActivityStatus('Could not copy scrape logs.', true);
      pushActivityScrapeLog('[Scrape] Failed to copy scrape logs.', { level: 'error' });
    }
  });
}

