if (activityDownloadSelectedBtn) {
  const baseActivityDownloadLabel = String(activityDownloadSelectedBtn.textContent || 'Download WEBP').trim() || 'Download WEBP';
  const setActivityDownloadButtonState = ({ loading = false, label = '' } = {}) => {
    const nextLoading = !!loading;
    activityDownloadSelectedBtn.classList.toggle('loading', nextLoading);
    activityDownloadSelectedBtn.disabled = nextLoading;
    activityDownloadSelectedBtn.textContent = String(label || (nextLoading ? 'Downloading...' : baseActivityDownloadLabel)).trim();
    activityDownloadSelectedBtn.setAttribute('aria-busy', nextLoading ? 'true' : 'false');
  };

  activityDownloadSelectedBtn.addEventListener('click', async () => {
    const selectedFromCards = collectSelectedActivityCardImages();
    const selectedImages = selectedFromCards.length
      ? selectedFromCards
      : activityResults.filter((item) => item.selected !== false && item.mediaType !== 'video');
    if (!selectedImages.length) {
      setActivityStatus('Select at least one activity image to download.', true);
      return;
    }

    activityDownloadPrefix = sanitizeDownloadPrefix(activityDownloadPrefixInput?.value || activityDownloadPrefix);
    localStorage.setItem(ACTIVITY_DOWNLOAD_PREFIX_KEY, activityDownloadPrefix);
    if (activityDownloadPrefixInput) activityDownloadPrefixInput.value = activityDownloadPrefix;

    const total = selectedImages.length;
    setActivityDownloadButtonState({ loading: true, label: `Downloading 0/${total}` });
    setActivityStatus(`Preparing ${total} selected image${total === 1 ? '' : 's'}...`);
    let completed = 0;
    let failed = 0;
    try {
      const canSaveToFolder =
        !!window.electronAPI?.selectImageSaveTarget &&
        !!window.electronAPI?.getImageSequenceNextIndex &&
        !!window.electronAPI?.saveImageFile;
      let resolvedDirectoryPath = '';
      let startIndex = 1;
      let saveToDirectory = false;

      if (canSaveToFolder) {
        const target = await resolveActivityBulkSaveTarget(activityDownloadPrefix);
        if (target?.canceled) {
          setActivityStatus('Download cancelled', true);
          return;
        }
        if (target?.error || !target?.directoryPath) {
          const reason = target?.error || 'Could not resolve save location.';
          pushActivityScrapeLog('[Download] Save target unavailable. Falling back to browser download.', {
            level: 'warn',
            details: { reason }
          });
          setActivityStatus(`Save location unavailable. Falling back to browser download (${reason})`, true);
        } else {
          activityDownloadPrefix = sanitizeDownloadPrefix(target.prefix || activityDownloadPrefix);
          localStorage.setItem(ACTIVITY_DOWNLOAD_PREFIX_KEY, activityDownloadPrefix);
          if (activityDownloadPrefixInput) activityDownloadPrefixInput.value = activityDownloadPrefix;
          resolvedDirectoryPath = String(target.directoryPath || '').trim();
          startIndex = Math.max(0, Number(target.nextIndex) || 0);
          saveToDirectory = !!resolvedDirectoryPath;
        }
      }

      for (let i = 0; i < selectedImages.length; i += 1) {
        const item = selectedImages[i];
        const filename = `${activityDownloadPrefix}_${startIndex + i}.webp`;
        let webpBlob = null;
        let itemSucceeded = false;
        try {
          webpBlob = await fetchImageAsWebpBlob(item.url);
        } catch (err) {
          failed += 1;
          pushActivityScrapeLog(`[Download] WEBP conversion failed for ${filename}`, {
            level: 'error',
            details: { error: String(err?.message || 'Unknown error'), url: item.url }
          });
          setActivityDownloadButtonState({
            loading: true,
            label: `Downloading ${Math.min(total, i + 1)}/${total}`
          });
          continue;
        }

        if (saveToDirectory) {
          try {
            const saveRes = await saveWebpBlobToDirectory({
              webpBlob,
              directoryPath: resolvedDirectoryPath,
              filename
            });
            if (saveRes?.success) {
              itemSucceeded = true;
            } else {
              pushActivityScrapeLog(`[Download] Save failed for ${filename}. Falling back to browser download.`, {
                level: 'warn',
                details: { error: saveRes?.error || 'Unknown save error', url: item.url }
              });
            }
          } catch (err) {
            pushActivityScrapeLog(`[Download] Save failed for ${filename}. Falling back to browser download.`, {
              level: 'warn',
              details: { error: String(err?.message || 'Unknown save error'), url: item.url }
            });
          }
        }

        if (!itemSucceeded) {
          try {
            triggerBlobDownload(webpBlob, filename);
            itemSucceeded = true;
          } catch (err) {
            pushActivityScrapeLog(`[Download] Browser download failed for ${filename}`, {
              level: 'error',
              details: { error: String(err?.message || 'Unknown error'), url: item.url }
            });
          }
        }

        if (itemSucceeded) completed += 1;
        else failed += 1;

        setActivityDownloadButtonState({
          loading: true,
          label: `Downloading ${Math.min(total, i + 1)}/${total}`
        });
      }

      if (saveToDirectory) {
        setActivityStatus(
          failed
            ? `Saved/downloaded ${completed} WEBP image(s); ${failed} failed.`
            : `Saved ${completed} WEBP image(s) starting at ${activityDownloadPrefix}_${startIndex}.webp`,
          failed > 0
        );
      } else {
        setActivityStatus(
          failed
            ? `Downloaded ${completed} WEBP image(s); ${failed} failed.`
            : `Downloaded ${completed} WEBP image(s) with prefix "${activityDownloadPrefix}"`,
          failed > 0
        );
      }
    } finally {
      setActivityDownloadButtonState({ loading: false, label: baseActivityDownloadLabel });
      renderActivityResults();
      updateActivityDownloadSelectionUi();
    }
  });
}

