const applySaveRecordByType = (save) => {
  if (!save) return;
  if (save.type === 'batch') applyBatchState(save.data || {});
  else if (save.type === 'video') applyVideoState(save.data || {});
  else if (save.type === 'tiktok') applyTikTokState(save.data || {});
  else applyState(save.data || {});
};
let restoredActiveProject = false;
const storedSessionActive = sessionStorage.getItem(ACTIVE_SESSION_SAVE_KEY) || '';
if (storedSessionActive && sessionSaves.find((s) => s.name === storedSessionActive)) {
  const save = sessionSaves.find((s) => s.name === storedSessionActive);
  setActiveSave(storedSessionActive, { session: true });
  applySaveRecordByType(save);
  restoredActiveProject = true;
} else {
  const storedActive = localStorage.getItem(ACTIVE_SAVE_KEY) || '';
  if (storedActive && saves.find((s) => s.name === storedActive)) {
    const save = saves.find((s) => s.name === storedActive);
    setActiveSave(storedActive, { session: false });
    applySaveRecordByType(save);
    restoredActiveProject = true;
  }
}
if (!restoredActiveProject) {
  try {
    const raw = localStorage.getItem(LAST_ACTIVE_PROJECT_KEY) || '';
    const parsed = raw ? JSON.parse(raw) : null;
    const name = String(parsed?.name || '').trim();
    const persisted = name ? saves.find((s) => s.name === name) : null;
    if (persisted) {
      setActiveSave(name, { session: false });
      applySaveRecordByType(persisted);
      restoredActiveProject = true;
    } else if (name && parsed?.session && parsed?.data) {
      const type = parsed.type || 'image';
      const record = {
        id: generateSessionId(),
        name,
        type,
        data: parsed.data,
        createdAt: Date.now(),
        updatedAt: Date.now(),
        session: true
      };
      sessionSaves.unshift(record);
      persistSessionSaves(sessionSaves.slice(0, 50));
      setActiveSave(name, { session: true });
      applySaveRecordByType(record);
      restoredActiveProject = true;
    }
  } catch (_err) {}
}
